import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = 'City',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      radius="xl"
      shadow="md"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
      aria-label={`Weather in ${city}`}
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between" align="start" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text
              variant="overline"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              aria-label="City"
            >
              {city}
            </Text>
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-label="Current temperature"
            >
              {temperature}°{unit}
            </Text>
          </Stack>

          <Stack align="end" gap="var(--ggui-spacing-1, 4px)">
            <Text
              size="2xl"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-label="Weather condition icon and text"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        <Stack
          direction="horizontal"
          justify="between"
          wrap
          gap="var(--ggui-spacing-4, 16px)"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          }}
        >
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {humidity}%
            </Text>
          </Stack>

          <Stack gap="var(--ggui-spacing-1, 4px)" align="end">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind
            </Text>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {windSpeed}
            </Text>
          </Stack>
        </Stack>

        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            5-Day Forecast
          </Text>

          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
            {forecast.map((item, index) => (
              <Stack
                key={`${item.day ?? 'day'}-${index}`}
                align="center"
                gap="var(--ggui-spacing-1, 4px)"
                style={{
                  flex: '1 1 90px',
                  minWidth: '90px',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                }}
                aria-label={`Forecast for ${item.day ?? 'day'}`}
              >
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day ?? '—'}
                </Text>
                <Text size="xl" color="var(--ggui-color-onSurface, #18181b)">
                  {item.icon ?? '—'}
                </Text>
                <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high ?? '—'}° / {item.low ?? '—'}°
                </Text>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Progress,
  RadioGroup,
  Checkbox,
  TextArea,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Survey */
  submit?: (answers: {
    name: string;
    email: string;
    satisfaction: string;
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

export default function GeneratedComponent({
  featureOptions = ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  submit,
}: Props) {
  const totalSteps = 5;
  const [step, setStep] = useState(1);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailValid
      ? 'Please enter a valid email address.'
      : '';

  const stepValid = useMemo(() => {
    if (step === 1) return Boolean(name.trim()) && Boolean(email.trim()) && emailValid;
    if (step === 2) return Boolean(satisfaction);
    return true;
  }, [step, name, email, emailValid, satisfaction]);

  const satisfactionOptions = satisfactionLabels.map((label, idx) => ({
    value: String(idx + 1),
    label,
  }));

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? (prev.includes(feature) ? prev : [...prev, feature]) : prev.filter((f) => f !== feature)
    );
  };

  const next = () => {
    if (step === 1) setTouched({ name: true, email: true });
    if (!stepValid) return;
    setStep((s) => Math.min(totalSteps, s + 1));
  };

  const back = () => setStep((s) => Math.max(1, s - 1));

  const handleSubmit = async () => {
    setFeedback(null);
    setIsSubmitting(true);
    try {
      await submit?.({
        name: name.trim(),
        email: email.trim(),
        satisfaction,
        featureInterests,
        comments: comments.trim(),
      });
      setFeedback({ type: 'success', message: 'Survey submitted successfully.' });
    } catch {
      setFeedback({ type: 'error', message: 'Submission failed. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={step} max={totalSteps} size="md" variant="default" />
        </Stack>

        {feedback && (
          <Alert variant={feedback.type === 'success' ? 'success' : 'error'} title={feedback.type === 'success' ? 'Success' : 'Error'}>
            {feedback.message}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              About You
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              error={nameError}
              placeholder="Enter your full name"
              aria-label="Name"
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError}
              placeholder="you@example.com"
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you?"
              value={satisfaction}
              onChange={setSatisfaction}
              options={satisfactionOptions}
              direction="vertical"
              error={!satisfaction ? 'Please select a rating before continuing.' : ''}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all features you are interested in.
            </Text>
            <Stack gap={8}>
              {featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={featureInterests.includes(feature)}
                  onChange={(checked) => toggleFeature(feature, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              rows={5}
              maxLength={500}
              showCount
              helperText="Share any additional feedback."
              aria-label="Comments"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Review Your Answers
            </Text>
            <Card
              padding={16}
              border
              shadow="none"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {name || '—'}</Text>
                <Text variant="body"><strong>Email:</strong> {email || '—'}</Text>
                <Text variant="body">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfaction ? satisfactionLabels[Number(satisfaction) - 1] ?? satisfaction : '—'}
                </Text>
                <Text variant="body">
                  <strong>Feature Interests:</strong> {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="body">
                  <strong>Comments:</strong> {comments.trim() || 'No comments'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" align="center">
          <Button variant="ghost" onPress={back} disabled={step === 1 || isSubmitting}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button variant="primary" onPress={next} disabled={!stepValid || isSubmitting}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onPress={handleSubmit} loading={isSubmitting} disabled={isSubmitting}>
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [search, setSearch] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColorMap = useMemo<Record<string, string>>(
    () => ({
      'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
      'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
      'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
      metalloid: 'var(--ggui-color-success-500, #22c55e)',
      nonmetal: 'var(--ggui-color-success-600, #16a34a)',
      halogen: 'var(--ggui-color-warning-600, #d97706)',
      'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
      lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
      actinide: 'var(--ggui-color-error-600, #dc2626)',
      unknown: 'var(--ggui-color-neutral-500, #6b7280)',
    }),
    []
  );

  const normalized = (v?: string) => (v || '').trim().toLowerCase();

  const filteredElements = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, search]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return undefined;
    return elements.find((el) => el.atomicNumber === selectedAtomicNumber);
  }, [elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      set.add(normalized(el.category) || 'unknown');
    });
    return Array.from(set);
  }, [elements]);

  return (
    <Card
      padding={16}
      shadow="sm"
      radius="lg"
      border
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          value={search}
          onChange={setSearch}
          placeholder="Search by name or symbol"
        />

        <Card
          padding={12}
          border
          radius="md"
          shadow="none"
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            {filteredElements.map((el) => {
              const categoryKey = normalized(el.category) || 'unknown';
              const borderColor =
                categoryColorMap[categoryKey] || 'var(--ggui-color-outline, #d4d4d8)';
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

              return (
                <Button
                  key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'x'}`}
                  variant="ghost"
                  size="sm"
                  aria-label={`Element ${el.name || 'Unknown'} (${el.symbol || '-'})`}
                  onPress={() =>
                    setSelectedAtomicNumber(
                      typeof el.atomicNumber === 'number' ? el.atomicNumber : null
                    )
                  }
                  style={{
                    gridRow: el.row ?? 'auto',
                    gridColumn: el.col ?? 'auto',
                    minHeight: '64px',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: `1px solid ${isSelected ? 'var(--ggui-color-onSurface, #18181b)' : borderColor}`,
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    position: 'relative',
                    transition: 'transform 120ms ease, box-shadow 120ms ease, border-color 120ms ease',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: '4px',
                      left: '6px',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      lineHeight: 1,
                    }}
                  >
                    {el.atomicNumber ?? '-'}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-lg, 18px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      lineHeight: 1,
                    }}
                  >
                    {el.symbol ?? '-'}
                  </span>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card padding={12} border radius="md" shadow="none">
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="body"><strong>Name:</strong> {selectedElement.name ?? '-'}</Text>
                <Text variant="body"><strong>Symbol:</strong> {selectedElement.symbol ?? '-'}</Text>
                <Text variant="body"><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '-'}</Text>
                <Text variant="body"><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '-'}</Text>
                <Text variant="body"><strong>Category:</strong> {selectedElement.category ?? 'unknown'}</Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card padding={12} border radius="md" shadow="none">
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((category) => {
                const c = categoryColorMap[category] || 'var(--ggui-color-outline, #d4d4d8)';
                return (
                  <div
                    key={category}
                    style={{
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-1, 4px)',
                      padding: '4px 8px',
                      border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    }}
                  >
                    <span
                      aria-hidden
                      style={{
                        width: '10px',
                        height: '10px',
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: c,
                        display: 'inline-block',
                      }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                      {category}
                    </Text>
                  </div>
                );
              })}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message — Called when user sends a message. Payload: { text, timestamp } */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = '',
    participantCount,
    messages = [],
    sendMessage,
  } = props;

  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  useEffect(() => {
    const node = listRef.current;
    if (node) node.scrollTop = node.scrollHeight;
  }, []);

  useEffect(() => {
    const node = listRef.current;
    if (node) node.scrollTop = node.scrollHeight;
  }, [allMessages.length]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const detail = customEvent?.detail;

      if (detail && typeof detail === 'object') {
        const maybeMessage = detail as { sender?: string; text?: string; timestamp?: string };
        if (maybeMessage.text || maybeMessage.sender || maybeMessage.timestamp) {
          setStreamMessages((prev) => [...prev, maybeMessage]);
        }
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    if (Number.isNaN(date.getTime())) return timestamp;
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    setDraft('');
  };

  const grouped = useMemo(() => {
    const groups: Array<{
      sender?: string;
      isCurrentUser: boolean;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const sender = msg.sender ?? '';
      const isCurrentUser = sender === currentUser;
      const last = groups[groups.length - 1];

      if (last && last.sender === sender) {
        last.items.push(msg);
      } else {
        groups.push({
          sender,
          isCurrentUser,
          items: [msg],
        });
      }
    });

    return groups;
  }, [allMessages, currentUser]);

  return (
    <Card
      padding={0}
      radius="lg"
      shadow="sm"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        height: '100%',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          {participantCount !== undefined ? (
            <Badge variant="primary" size="sm">
              {participantCount}
            </Badge>
          ) : null}
        </Stack>

        <Stack
          ref={listRef}
          gap={12}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          aria-label="Message list"
        >
          {grouped.map((group, groupIndex) => (
            <Stack
              key={`${group.sender ?? 'unknown'}-${groupIndex}`}
              gap={6}
              align={group.isCurrentUser ? 'end' : 'start'}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                align={group.isCurrentUser ? 'right' : 'left'}
              >
                {group.sender || 'Unknown'}
              </Text>

              {group.items.map((message, messageIndex) => (
                <Stack
                  key={`${groupIndex}-${messageIndex}-${message.timestamp ?? ''}`}
                  gap={4}
                  style={{
                    maxWidth: '80%',
                    padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    background: group.isCurrentUser
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    color: group.isCurrentUser
                      ? 'var(--ggui-color-surface, #fafafa)'
                      : 'var(--ggui-color-onSurface, #18181b)',
                    transition: 'background-color 200ms ease-in-out, box-shadow 200ms ease-in-out',
                  }}
                >
                  <Text
                    variant="bodySmall"
                    color={
                      group.isCurrentUser
                        ? 'var(--ggui-color-surface, #fafafa)'
                        : 'var(--ggui-color-onSurface, #18181b)'
                    }
                  >
                    {message.text || ''}
                  </Text>
                  <Text
                    variant="caption"
                    color={
                      group.isCurrentUser
                        ? 'var(--ggui-color-primary-100, #e0f2fe)'
                        : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                    }
                    align={group.isCurrentUser ? 'right' : 'left'}
                  >
                    {formatTime(message.timestamp)}
                  </Text>
                </Stack>
              ))}
            </Stack>
          ))}
        </Stack>

        <Stack
          direction="horizontal"
          gap={8}
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack style={{ flex: 1 }}>
            <Input
              label="Message"
              value={draft}
              onChange={setDraft}
              placeholder="Type a message..."
              aria-label="Compose message"
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </Stack>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const {
    stocks = [
      { symbol: 'AAPL', name: 'Apple Inc.', price: 189.34, change: 1.24, changePercent: 0.66 },
      { symbol: 'MSFT', name: 'Microsoft Corp.', price: 417.88, change: -2.13, changePercent: -0.51 },
      { symbol: 'GOOGL', name: 'Alphabet Inc.', price: 171.22, change: 0.92, changePercent: 0.54 },
    ],
    lastUpdated = new Date().toISOString(),
  } = props;

  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(stocks.length === 0);

  useEffect(() => {
    setLiveStocks(stocks);
    setLiveLastUpdated(lastUpdated);
    setIsLoading(stocks.length === 0);
  }, [stocks, lastUpdated]);

  useEffect(() => {
    let connectTimer: number | undefined;
    setIsConnecting(true);

    connectTimer = window.setTimeout(() => {
      setIsConnecting(false);
    }, 900);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const detail = customEvent.detail;

      if (detail?.stocks && Array.isArray(detail.stocks)) {
        setLiveStocks(detail.stocks);
        setIsLoading(detail.stocks.length === 0);
      }
      if (typeof detail?.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
      } else {
        setLiveLastUpdated(new Date().toISOString());
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data', handleAgentData);

    return () => {
      if (connectTimer) window.clearTimeout(connectTimer);
      window.removeEventListener('ggui:agent-data', handleAgentData);
    };
  }, []);

  const formattedLastUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="sm"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Text
            as="div"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Text>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
            {isConnecting && <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />}
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              aria-live="polite"
            >
              {isConnecting ? 'Connecting live feed…' : `Last Updated: ${formattedLastUpdated}`}
            </Text>
          </Stack>
        </Stack>

        {isLoading ? (
          <Card
            padding="var(--ggui-spacing-8, 32px)"
            radius="md"
            border
            shadow="none"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            }}
          >
            <Stack align="center" gap="var(--ggui-spacing-2, 8px)">
              <Spinner size={24} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Loading stock prices…
              </Text>
            </Stack>
          </Card>
        ) : (
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {liveStocks.map((stock, index) => {
              const symbol = stock.symbol ?? `TICK-${index + 1}`;
              const name = stock.name ?? 'Unknown Company';
              const price = typeof stock.price === 'number' ? stock.price : 0;
              const change = typeof stock.change === 'number' ? stock.change : 0;
              const changePercent = typeof stock.changePercent === 'number' ? stock.changePercent : 0;

              const isPositive = change >= 0;
              const trendColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const arrow = isPositive ? '▲' : '▼';

              return (
                <Card
                  key={`${symbol}-${index}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  radius="md"
                  shadow="sm"
                  border
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: trendColor,
                    transition: 'transform 200ms ease, box-shadow 200ms ease',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      as="div"
                      size="3xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      aria-label={`Ticker symbol ${symbol}`}
                    >
                      {symbol}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                      aria-label={`Company name ${name}`}
                    >
                      {name}
                    </Text>
                    <Text
                      as="div"
                      size="xl"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      aria-label={`Current price ${price.toFixed(2)}`}
                    >
                      ${price.toFixed(2)}
                    </Text>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text
                        variant="label"
                        color={trendColor}
                        aria-label={`Change amount ${change.toFixed(2)}`}
                      >
                        {change >= 0 ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>
                      <Text
                        variant="label"
                        color={trendColor}
                        aria-label={`Change percentage ${changePercent.toFixed(2)} percent`}
                      >
                        {arrow} {changePercent >= 0 ? '+' : ''}
                        {changePercent.toFixed(2)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </div>
        )}
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);

  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions[0] ?? ''
  );

  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

  const nameError = name.trim() ? '' : 'Name is required';
  const emailError = email.trim()
    ? isValidEmail(email)
      ? ''
      : 'Please enter a valid email address'
    : 'Email is required';

  const step1Valid = Boolean(name.trim() && email.trim() && isValidEmail(email));
  const step2Valid = Boolean(role);

  const canNext = step === 1 ? step1Valid : step === 2 ? step2Valid : true;

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const handleNext = () => {
    if (!canNext) return;
    setStep((s) => Math.min(3, s + 1));
  };

  const handleBack = () => setStep((s) => Math.max(1, s - 1));

  const handleComplete = () => {
    props.complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <Card
      padding={24}
      radius="lg"
      shadow="md"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <MotionKeyframes />
      <Stack gap={20}>
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Onboarding Wizard
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} / 3
            </Text>
          </Stack>
          <Progress value={progressValue} max={100} size="md" variant="default" />
        </Stack>

        <Card
          padding={16}
          shadow="none"
          radius="md"
          border
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
          }}
        >
          {step === 1 && (
            <Stack gap={16}>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Step 1 - Profile Setup
              </Text>
              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                error={nameError || undefined}
                placeholder="Enter your name"
                aria-label="Name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                error={emailError || undefined}
                placeholder="Enter your email"
                aria-label="Email"
              />
              <Stack gap={8}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Choose Avatar
                </Text>
                <Stack direction="horizontal" gap={8} wrap>
                  {props.avatarOptions.map((option) => {
                    const isSelected = option === avatar;
                    return (
                      <Button
                        key={option}
                        variant={isSelected ? 'primary' : 'outline'}
                        size="sm"
                        onClick={() => setAvatar(option)}
                        aria-label={`Select avatar ${option}`}
                      >
                        {option}
                      </Button>
                    );
                  })}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Step 2 - Preferences
              </Text>
              <Select
                label="Role"
                value={role}
                onChange={setRole}
                placeholder="Select your role"
                required
                options={props.roleOptions.map((r) => ({ label: r, value: r }))}
                error={!role ? 'Role is required' : undefined}
                aria-label="Role"
              />
              <Toggle
                label="Email notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
              />
              <Toggle
                label={`Theme preference (${theme === 'dark' ? 'Dark' : 'Light'})`}
                checked={theme === 'dark'}
                onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={14}>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Step 3 - Review & Confirm
              </Text>
              <Card
                padding={14}
                shadow="none"
                radius="md"
                border
                style={{
                  background: 'var(--ggui-color-surface, #fafafa)',
                  borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                }}
              >
                <Stack gap={8}>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    <strong>Name:</strong> {name || '-'}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    <strong>Email:</strong> {email || '-'}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    <strong>Avatar:</strong> {avatar || '-'}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    <strong>Role:</strong> {role || '-'}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    <strong>Theme:</strong> {theme}
                  </Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Card>

        <Stack direction="horizontal" justify="between" align="center">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1}
            aria-label="Go back to previous step"
          >
            Back
          </Button>

          {step < 3 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canNext}
              aria-label="Go to next step"
            >
              Next
            </Button>
          ) : (
            <Stack direction="horizontal" gap={8}>
              <Button variant="outline" onClick={handleBack} aria-label="Go back and edit">
                Go Back
              </Button>
              <Button variant="primary" onClick={handleComplete} aria-label="Complete setup">
                Complete Setup
              </Button>
            </Stack>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const conditionToIcon = (condition: string): string => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('blizzard')) return '❄️';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
  if (normalized.includes('wind')) return '💨';
  return '🌤️';
};

export default function GeneratedComponent({
  city = '—',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const resolvedUnit = unit || 'C';
  const displayConditionIcon = conditionToIcon(condition);

  return (
    <Card
      shadow="md"
      radius="xl"
      padding="var(--ggui-spacing-6, 24px)"
      border
      role="region"
      aria-label={`Weather for ${city}`}
    >
      <Stack
        direction="vertical"
        gap="var(--ggui-spacing-4, 16px)"
        style={{
          color: 'var(--ggui-color-onSurface, #18181b)',
        }}
      >
        <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
          <Heading
            level={4}
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {city}
          </Heading>
        </Stack>

        <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
          <Text
            variant="body"
            size="4xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {temperature}°{resolvedUnit}
          </Text>
          <Text
            variant="bodyLarge"
            weight="medium"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {displayConditionIcon} {condition}
          </Text>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          wrap
          gap="var(--ggui-spacing-4, 16px)"
        >
          <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {windSpeed}
            </Text>
          </Stack>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="vertical" gap="var(--ggui-spacing-2, 8px)">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              5-Day Forecast
            </Text>

            {forecast.length === 0 ? (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No forecast data
              </Text>
            ) : (
              <Stack
                direction="horizontal"
                justify="between"
                wrap
                gap="var(--ggui-spacing-4, 16px)"
                role="list"
              >
                {forecast.slice(0, 5).map((item, index) => {
                  const day = item.day ?? '—';
                  const icon = item.icon ?? '🌤️';
                  const high = item.high ?? '—';
                  const low = item.low ?? '—';

                  return (
                    <Stack
                      key={`${day}-${index}`}
                      direction="vertical"
                      align="center"
                      gap={4}
                      role="listitem"
                    >
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {day}
                      </Text>
                      <Text as="span" size="xl" color="var(--ggui-color-primary-600, #0284c7)">
                        {icon}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                        {high}° / {low}°
                      </Text>
                    </Stack>
                  );
                })}
              </Stack>
            )}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface SurveyAnswers {
  name: string;
  email: string;
  satisfaction: string;
  featureInterests: string[];
  comments: string;
}

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit callback from action contract */
  onSubmit?: (answers: SurveyAnswers) => Promise<void> | void;
  /** Optional heading text */
  title?: string;
  /** Optional description text */
  description?: string;
  /** Optional label overrides */
  labels?: {
    name?: string;
    email?: string;
    comments?: string;
    back?: string;
    next?: string;
    submit?: string;
    review?: string;
  };
}

const defaultFeatureOptions = ['Analytics', 'Automation', 'Integrations'];
const defaultSatisfactionLabels = [
  'Very Unsatisfied',
  'Unsatisfied',
  'Neutral',
  'Satisfied',
  'Very Satisfied',
];

export default function GeneratedComponent({
  featureOptions = defaultFeatureOptions,
  satisfactionLabels = defaultSatisfactionLabels,
  onSubmit,
  title = 'Customer Experience Survey',
  description = 'Please complete all required steps before submitting.',
  labels = {},
}: Props) {
  const [step, setStep] = useState(1);
  const totalSteps = 5; // includes final review step

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState({
    name: false,
    email: false,
    satisfaction: false,
  });

  const [submitting, setSubmitting] = useState(false);
  const [status, setStatus] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailValid
      ? 'Please enter a valid email address.'
      : '';
  const satisfactionError = touched.satisfaction && !satisfaction ? 'Please select a rating.' : '';

  const stepValid = useMemo(() => {
    if (step === 1) return name.trim().length > 0 && emailValid;
    if (step === 2) return satisfaction.length > 0;
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    if (step === 5) return true;
    return false;
  }, [step, name, emailValid, satisfaction, comments.length]);

  const progressValue = (step / totalSteps) * 100;

  const satisfactionOptions = satisfactionLabels.slice(0, 5).map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const toggleFeature = (option: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, option] : prev.filter((item) => item !== option),
    );
  };

  const goNext = () => {
    if (step === 1) {
      setTouched((p) => ({ ...p, name: true, email: true }));
      if (!name.trim() || !emailValid) return;
    }
    if (step === 2) {
      setTouched((p) => ({ ...p, satisfaction: true }));
      if (!satisfaction) return;
    }
    if (step < totalSteps) setStep((s) => s + 1);
  };

  const goBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const handleSubmit = async () => {
    setStatus(null);
    const payload: SurveyAnswers = {
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      featureInterests,
      comments: comments.trim(),
    };

    try {
      setSubmitting(true);
      await onSubmit?.(payload);
      setStatus({ type: 'success', message: 'Survey submitted successfully.' });
    } catch (error) {
      setStatus({ type: 'error', message: 'Submission failed. Please try again.' });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        maxWidth: 760,
        margin: '0 auto',
      }}
    >
      <Stack gap={16}>
        <Stack gap={6}>
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {description}
          </Text>
        </Stack>

        <Stack gap={6}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-live="polite"
            aria-atomic="true"
          >
            Step {step} of {totalSteps}
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        {status && (
          <Alert variant={status.type === 'success' ? 'success' : 'error'} title={status.message}>
            {status.type === 'success'
              ? 'Thank you for sharing your feedback.'
              : 'Please review your answers and try again.'}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Input
              label={labels.name || 'Name'}
              value={name}
              onChange={setName}
              required
              error={nameError}
              placeholder="Enter your full name"
              aria-label="Name"
            />
            <Input
              label={labels.email || 'Email'}
              value={email}
              onChange={setEmail}
              required
              type="email"
              error={emailError}
              placeholder="you@example.com"
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="How satisfied are you?"
            value={satisfaction}
            onChange={setSatisfaction}
            options={satisfactionOptions}
            error={satisfactionError}
            direction="vertical"
          />
        )}

        {step === 3 && (
          <Stack gap={10}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Which features interest you?
            </Text>
            {featureOptions.map((option) => (
              <Checkbox
                key={option}
                label={option}
                checked={featureInterests.includes(option)}
                onChange={(checked) => toggleFeature(option, checked)}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <TextArea
            label={labels.comments || 'Additional comments (optional)'}
            value={comments}
            onChange={setComments}
            rows={6}
            maxLength={500}
            showCount
            helperText="You can share any additional suggestions."
            aria-label="Additional comments"
          />
        )}

        {step === 5 && (
          <Stack gap={10}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {labels.review || 'Review your answers'}
            </Text>
            <Card
              padding={16}
              shadow="none"
              border
              radius="md"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="bodySmall">
                  <strong>Name:</strong> {name || '—'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Email:</strong> {email || '—'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfaction
                    ? satisfactionOptions.find((o) => o.value === satisfaction)?.label || satisfaction
                    : '—'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Feature interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Comments:</strong> {comments.trim() || 'No additional comments'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={8}>
          <Button
            variant="ghost"
            onClick={goBack}
            disabled={step === 1 || submitting}
            aria-label="Go to previous step"
          >
            {labels.back || 'Back'}
          </Button>

          {step < totalSteps ? (
            <Button
              variant="primary"
              onClick={goNext}
              disabled={!stepValid || submitting}
              aria-label="Go to next step"
            >
              {labels.next || 'Next'}
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              loading={submitting}
              disabled={submitting}
              aria-label="Submit survey"
            >
              {labels.submit || 'Submit Survey'}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input } from '@ggui-ai/design/primitives';

interface Props {
