    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'transition metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'post-transition metal': 'var(--ggui-color-info-100, #cffafe)',
  metalloid: 'var(--ggui-color-success-100, #dcfce7)',
  nonmetal: 'var(--ggui-color-neutral-100, #f3f4f6)',
  halogen: 'var(--ggui-color-warning-500, #f59e0b)',
  'noble gas': 'var(--ggui-color-primary-200, #bae6fd)',
  lanthanide: 'var(--ggui-color-success-500, #22c55e)',
  actinide: 'var(--ggui-color-error-500, #ef4444)',
};

const fallbackCategoryColor = 'var(--ggui-color-surfaceVariant, #f4f4f5)';

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [query, setQuery] = useState<string>('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][number] | null>(null);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    elements.forEach((el) => {
      if (el.category) unique.add(el.category);
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [elements]);

  return (
    <Card
      padding={16}
      shadow="sm"
      border
      radius="lg"
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Interactive Periodic Table
        </Text>

        <Input
          label="Search elements"
          placeholder="Search by name or symbol"
          type="search"
          value={query}
          onChange={setQuery}
          aria-label="Search elements by name or symbol"
        />

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            {filteredElements.map((el, index) => {
              const categoryKey = (el.category ?? '').toLowerCase();
              const bg = categoryColorMap[categoryKey] ?? fallbackCategoryColor;
              const isSelected =
                selectedElement?.atomicNumber !== undefined &&
                selectedElement.atomicNumber === el.atomicNumber;

              return (
                <button
                  key={`${el.atomicNumber ?? 'unknown'}-${el.symbol ?? 'x'}-${index}`}
                  type="button"
                  onClick={() => setSelectedElement(el)}
                  aria-label={`Element ${el.name ?? 'Unknown'} (${el.symbol ?? '-'})`}
                  style={{
                    gridColumn: el.col ? `${el.col}` : 'auto',
                    gridRow: el.row ? `${el.row}` : 'auto',
                    position: 'relative',
                    minHeight: '56px',
                    border: isSelected
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    background: bg,
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    cursor: 'pointer',
                    transition:
                      'background-color 200ms ease, border-color 200ms ease, transform 100ms ease',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    textAlign: 'center',
                  }}
                >
                  <Text
                    as="span"
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{
                      position: 'absolute',
                      top: '4px',
                      left: '6px',
                    } as React.CSSProperties}
                  >
                    {el.atomicNumber ?? '-'}
                  </Text>
                  <Text
                    as="span"
                    weight="bold"
                    size="lg"
                    color="var(--ggui-color-onSurface, #18181b)"
                    style={{
                      display: 'inline-block',
                      marginTop: '12px',
                    } as React.CSSProperties}
                  >
                    {el.symbol ?? '?'}
                  </Text>
                </button>
              );
            })}
          </div>
        </Card>

        <Card padding={12} border shadow="none" radius="md">
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" gap={8} wrap>
              {categories.map((cat) => {
                const color = categoryColorMap[cat.toLowerCase()] ?? fallbackCategoryColor;
                return (
                  <div
                    key={cat}
                    style={{
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-1, 4px)',
                      padding: '4px 8px',
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      background: 'var(--ggui-color-surface, #fafafa)',
                    }}
                  >
                    <span
                      aria-hidden="true"
                      style={{
                        width: '10px',
                        height: '10px',
                        borderRadius: '9999px',
                        background: color,
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      }}
                    />
                    <Text as="span" variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                      {cat}
                    </Text>
                  </div>
                );
              })}
            </Stack>
          </Stack>
        </Card>

        <Card padding={12} border shadow="none" radius="md">
          <Stack gap={6}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Name: {selectedElement.name ?? '-'}
                </Text>
