                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Category: {selectedElement.category ?? '-'}
                </Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element from the grid to view details.
              </Text>
            )}
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  Badge,
  Box,
  Button,
  Card,
  Heading,
  Input,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type NormalizedMessage = {
  sender: string;
  text: string;
  timestamp: string;
};

type MessageGroup = {
  sender: string;
  isCurrentUser: boolean;
  items: Array<{ text: string; timestamp: string }>;
};

export default function GeneratedComponent({
  title = '',
  currentUser = '',
  participantCount = undefined,
  messages = [],
  sendMessage = undefined,
}: Props) {
  const [draft, setDraft] = useState<string>('');
  const [streamMessages, setStreamMessages] = useState<NormalizedMessage[]>([]);
  const scrollRef = useRef<HTMLDivElement | null>(null);

  const normalizeMessage = (msg: { sender?: string; text?: string; timestamp?: string }): NormalizedMessage => ({
    sender: msg.sender ?? 'Unknown',
    text: msg.text ?? '',
    timestamp: msg.timestamp ?? '',
  });

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<Record<string, unknown> | undefined>;
      const detail = customEvent?.detail ?? {};
      const sender =
        typeof detail?.sender === 'string'
          ? detail.sender
          : typeof detail?.name === 'string'
          ? detail.name
          : 'Agent';
      const text =
        typeof detail?.text === 'string'
          ? detail.text
          : typeof detail?.message === 'string'
          ? detail.message
          : '';
      const timestamp =
        typeof detail?.timestamp === 'string' ? detail.timestamp : new Date().toISOString();

      setStreamMessages((prev) => [...prev, { sender, text, timestamp }]);
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  const combinedMessages = useMemo<NormalizedMessage[]>(
    () => [...messages.map(normalizeMessage), ...streamMessages],
    [messages, streamMessages]
  );

  const groups = useMemo<MessageGroup[]>(() => {
    const result: MessageGroup[] = [];
    combinedMessages.forEach((msg) => {
      const isCurrentUser = msg.sender === currentUser;
      const last = result[result.length - 1];
      if (!last || last.sender !== msg.sender) {
        result.push({
          sender: msg.sender,
          isCurrentUser,
          items: [{ text: msg.text, timestamp: msg.timestamp }],
        });
      } else {
        last.items.push({ text: msg.text, timestamp: msg.timestamp });
      }
    });
    return result;
  }, [combinedMessages, currentUser]);

  const formatTimestamp = (timestamp: string): string => {
    if (!timestamp) return '';
    const d = new Date(timestamp);
    if (Number.isNaN(d.getTime())) return timestamp;
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    setDraft('');
  };

  const trimmedDraft = draft.trim();

  return (
    <Card
      padding={0}
      shadow="sm"
      border
      radius="lg"
      role="region"
      aria-label={title || 'Chat'}
    >
      <Stack
        gap={0}
        style={{
          height: 'var(--ggui-chat-height, 560px)',
          background: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <Box
          padding="var(--ggui-spacing-4, 16px)"
          style={{
            borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack direction="horizontal" justify="between" align="center">
            <Heading
              level={5}
              color="var(--ggui-color-onSurface, #18181b)"
              style={{
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
            >
              {title}
            </Heading>
            {participantCount !== undefined ? (
              <Badge variant="secondary" size="sm" pill>
                {`${participantCount} participants`}
              </Badge>
            ) : null}
          </Stack>
        </Box>

        <Box
          ref={scrollRef}
          role="log"
          aria-live="polite"
          aria-relevant="additions text"
          aria-label="Messages"
          padding="var(--ggui-spacing-4, 16px)"
          style={{
            flex: 1,
            overflowY: 'auto',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack gap="var(--ggui-spacing-4, 16px)">
            {groups.map((group, groupIndex) => (
              <Box
                key={`${group.sender}-${groupIndex}`}
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: group.isCurrentUser ? 'flex-end' : 'flex-start',
                  gap: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                <Text
                  variant="label"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {group.sender}
                </Text>

                <Stack gap="var(--ggui-spacing-2, 8px)" align={group.isCurrentUser ? 'end' : 'start'}>
                  {group.items.map((item, itemIndex) => {
                    const isCurrent = group.isCurrentUser;
                    return (
                      <Box
                        key={`${group.sender}-${groupIndex}-${itemIndex}`}
                        padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                        style={{
                          maxWidth: '80%',
                          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                          background: isCurrent
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                          color: isCurrent
                            ? 'var(--ggui-color-neutral-50, #f9fafb)'
                            : 'var(--ggui-color-onSurface, #18181b)',
                          border: isCurrent
                            ? 'none'
                            : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                        }}
                      >
                        <Stack gap={4}>
                          <Text
                            variant="body"
                            color={
                              isCurrent
                                ? 'var(--ggui-color-neutral-50, #f9fafb)'
                                : 'var(--ggui-color-onSurface, #18181b)'
                            }
                          >
                            {item.text}
                          </Text>
                          <Text
                            variant="caption"
                            color={
                              isCurrent
                                ? 'var(--ggui-color-neutral-100, #f3f4f6)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                            align={isCurrent ? 'right' : 'left'}
                          >
                            {formatTimestamp(item.timestamp)}
                          </Text>
                        </Stack>
                      </Box>
                    );
                  })}
                </Stack>
              </Box>
            ))}
          </Stack>
        </Box>

        <Box
          padding="var(--ggui-spacing-4, 16px)"
          style={{
            borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder=""
                value={draft}
                onChange={setDraft}
                size="md"
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button
              variant="primary"
              size="md"
              onClick={handleSend}
              disabled={trimmedDraft.length === 0}
              aria-label="Send message"
            >
              Send
            </Button>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

export const __GGUI_META__ = {
  category: 'interaction',
  description:
    'Reusable real-time chat interface with grouped message bubbles, stream listener, auto-scroll, and send action wiring.',
};

import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Box,
  Card,
  Container,
  Heading,
  Spinner,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

type ConnectionState = 'connecting' | 'live' | 'reconnecting' | 'error';

const formatTimestamp = (value?: string): string => {
  if (!value) return '—';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '—';
  return date.toLocaleString();
};

const formatPrice = (value?: number): string => `$${(value ?? 0).toFixed(2)}`;

const formatSigned = (value?: number): string => {
  const safe = value ?? 0;
  if (safe > 0) return `+${safe.toFixed(2)}`;
  if (safe < 0) return `${safe.toFixed(2)}`;
  return '0.00';
};

const formatPercent = (value?: number): string => `${formatSigned(value)}%`;

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = undefined,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [connectionState, setConnectionState] = useState<ConnectionState>('connecting');
  const [isInitialLoading, setIsInitialLoading] = useState<boolean>(stocks.length === 0);
  const [streamError, setStreamError] = useState<string | undefined>(undefined);
  const [isDesktop, setIsDesktop] = useState<boolean>(() =>
    typeof window !== 'undefined' ? window.innerWidth >= 1024 : false,
  );
  const [lastEventAt, setLastEventAt] = useState<number>(() => Date.now());

  useEffect(() => {
    setLiveStocks(stocks);
    setLiveLastUpdated(lastUpdated);
    if (stocks.length > 0) {
      setIsInitialLoading(false);
      setConnectionState((prev) => (prev === 'error' ? prev : 'live'));
    }
  }, [stocks, lastUpdated]);

  useEffect(() => {
    const onResize = () => setIsDesktop(window.innerWidth >= 1024);
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  useEffect(() => {
    const handler = (event: Event) => {
      try {
        const customEvent = event as CustomEvent<unknown>;
        const detail = customEvent.detail as
          | {
              stocks?: Props['stocks'];
              lastUpdated?: string;
              status?: string;
              error?: string;
            }
          | undefined;

        const nextStocks = detail?.stocks;
        const nextLastUpdated = detail?.lastUpdated;

        if (detail?.error) {
          setStreamError(detail.error);
          setConnectionState('error');
          setIsInitialLoading(false);
          return;
        }

        const hasValidStocks = Array.isArray(nextStocks);
        const hasValidTimestamp = typeof nextLastUpdated === 'string' || nextLastUpdated === undefined;

        if (!hasValidStocks && !hasValidTimestamp) {
          setStreamError('Malformed live data payload received.');
          setConnectionState('error');
          setIsInitialLoading(false);
          return;
        }

        if (hasValidStocks) {
          setLiveStocks(nextStocks ?? []);
        }
        if (typeof nextLastUpdated === 'string') {
          setLiveLastUpdated(nextLastUpdated);
        }

        setStreamError(undefined);
        setConnectionState('live');
        setIsInitialLoading(false);
        setLastEventAt(Date.now());
      } catch {
        setStreamError('Failed to process live data stream.');
        setConnectionState('error');
        setIsInitialLoading(false);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  useEffect(() => {
    const interval = window.setInterval(() => {
      const age = Date.now() - lastEventAt;
      if (connectionState !== 'error' && age > 10000) {
        setConnectionState('reconnecting');
      }
    }, 2000);

    return () => window.clearInterval(interval);
  }, [connectionState, lastEventAt]);

  const connectionLabel = useMemo(() => {
    if (connectionState === 'live') return 'Live';
    if (connectionState === 'reconnecting') return 'Reconnecting';
    if (connectionState === 'error') return 'Connection error';
    if (isInitialLoading) return 'Connecting';
    return 'Waiting for data';
  }, [connectionState, isInitialLoading]);

  const showEmptyLoading = liveStocks.length === 0 && (isInitialLoading || connectionState !== 'live');
  const showEmptyIdle = liveStocks.length === 0 && !showEmptyLoading;

  return (
    <Container
      maxWidth="xl"
      padding="var(--ggui-spacing-6, 24px)"
    >
      <Stack
        gap="var(--ggui-spacing-6, 24px)"
      >
        <Box
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          padding="var(--ggui-spacing-2, 8px)"
        >
          <Stack
            direction="horizontal"
            justify="between"
            align="center"
            wrap
            gap="var(--ggui-spacing-2, 8px)"
          >
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>

            <Stack gap={2} aria-live="polite">
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Last Updated: {formatTimestamp(liveLastUpdated)}
              </Text>
              <Text
                variant="bodySmall"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {connectionLabel}
              </Text>
            </Stack>
          </Stack>
        </Box>

        {streamError ? (
          <Alert variant="error" title="Live stream issue">
            {streamError}
          </Alert>
        ) : null}

        <Box
          role="list"
          style={{
            display: 'grid',
            gridTemplateColumns: isDesktop ? 'repeat(3, minmax(0, 1fr))' : '1fr',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {showEmptyLoading ? (
            <Card
              padding={24}
              shadow="sm"
              radius="lg"
              border
              style={{
                gridColumn: '1 / -1',
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack align="center" gap="var(--ggui-spacing-2, 8px)">
                <Spinner size={22} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Connecting to live market feed...
                </Text>
              </Stack>
            </Card>
          ) : null}

          {showEmptyIdle ? (
            <Card
              padding={24}
              shadow="sm"
              radius="lg"
              border
              style={{
                gridColumn: '1 / -1',
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stock data available.
              </Text>
            </Card>
          ) : null}

          {liveStocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) > 0 || (stock.changePercent ?? 0) > 0;
            const isNegative = (stock.change ?? 0) < 0 || (stock.changePercent ?? 0) < 0;
            const isNeutral = !isPositive && !isNegative;

            const accentColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : isNegative
              ? 'var(--ggui-color-error-600, #dc2626)'
              : 'var(--ggui-color-onSurfaceVariant, #52525b)';

            const borderColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : isNegative
              ? 'var(--ggui-color-error-600, #dc2626)'
              : 'var(--ggui-color-outline, #d4d4d8)';

            const arrow = isPositive ? '▲' : isNegative ? '▼' : '';

            return (
              <Card
                key={stock.symbol || index}
                role="listitem"
                padding={16}
                shadow="sm"
                radius="lg"
                border
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor,
                  transition: 'border-color 200ms ease-in-out, color 200ms ease-in-out',
                }}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text
                    variant="body"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {stock.symbol || '—'}
                  </Text>

                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {stock.name || 'Unknown Company'}
                  </Text>

                  <Text
                    variant="bodyLarge"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {formatPrice(stock.price)}
                  </Text>

                  <Stack
                    direction="horizontal"
                    align="center"
                    gap="var(--ggui-spacing-2, 8px)"
                  >
                    <Text
                      variant="bodySmall"
                      weight="medium"
                      color={accentColor}
                    >
                      {formatSigned(stock.change)}
                    </Text>
                    <Text
                      variant="bodySmall"
                      weight="semibold"
                      color={isNeutral ? 'var(--ggui-color-onSurfaceVariant, #52525b)' : accentColor}
                    >
                      {arrow ? `${arrow} ` : ''}
                      {formatPercent(stock.changePercent)}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Box,
  Button,
  Card,
  Container,
  Divider,
  Heading,
  Input,
  MotionKeyframes,
  Progress,
  Select,
  Stack,
  Text,
  Toggle,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];

  /** Action Contract: Complete Setup */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ['😀', '😎', '🤓', '🚀'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  onComplete = () => {},
}: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState<number>(1);

  const [name, setName] = useState<string>(initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile?.avatar ?? (avatarOptions[0] ?? ''));
  const [role, setRole] = useState<string>(initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    initialProfile?.emailNotifications ?? false
  );
  const [theme, setTheme] = useState<string>(initialProfile?.theme ?? 'light');

  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({
    name: false,
    email: false,
  });
  const [attemptedNext, setAttemptedNext] = useState<boolean>(false);

  useEffect(() => {
    setName(initialProfile?.name ?? '');
    setEmail(initialProfile?.email ?? '');
    setAvatar(initialProfile?.avatar ?? (avatarOptions[0] ?? ''));
    setRole(initialProfile?.role ?? '');
    setEmailNotifications(initialProfile?.emailNotifications ?? false);
    setTheme(initialProfile?.theme ?? 'light');
  }, [initialProfile, avatarOptions]);

  useEffect(() => {
    if (avatarOptions.length === 0) {
      setAvatar('');
      return;
    }
    if (!avatarOptions.includes(avatar)) {
      setAvatar(avatarOptions[0]);
    }
  }, [avatarOptions, avatar]);

  const isNameValid = useMemo(() => name.trim().length > 0, [name]);
  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const isStep1Valid = isNameValid && isEmailValid;
  const isStep2Valid = role.trim().length > 0;

  const progressValue = useMemo(() => (currentStep / 3) * 100, [currentStep]);

  const showNameError = (touched.name || attemptedNext) && !isNameValid;
  const showEmailError = (touched.email || attemptedNext) && !isEmailValid;

  const handleNext = () => {
    if (currentStep === 1) {
      setAttemptedNext(true);
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      if (!isStep1Valid) return;
      setCurrentStep(2);
      setAttemptedNext(false);
      return;
    }

    if (currentStep === 2) {
      if (!isStep2Valid) return;
      setCurrentStep(3);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  };

  const handleComplete = () => {
    onComplete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  const stepAnimationStyle = motionEnabled
    ? { animation: 'ggui-slideInUp 200ms ease-out' }
    : { animation: 'none' };

  const roleSelectOptions = roleOptions.map((r) => ({ value: r, label: r }));
  const displayedAvatars = avatarOptions.length > 0 ? avatarOptions : ['😀', '😎', '🤓', '🚀'];

  const canGoNext =
    (currentStep === 1 && isStep1Valid) || (currentStep === 2 && isStep2Valid) || currentStep === 3;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Card
        shadow="md"
        radius="lg"
        border
        padding={24}
      >
        <Stack gap={16}>
          <Stack gap={8}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
              Onboarding Setup
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {currentStep} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          <Divider color="var(--ggui-color-outline, #d4d4d8)" margin={0} />

          <Box
            padding={0}
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack gap={16} style={stepAnimationStyle}>
              {currentStep === 1 && (
                <Stack gap={16}>
                  <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">
                    Profile Setup
                  </Heading>

                  <Input
                    label="Name"
                    value={name}
                    onChange={(value) => {
                      setName(value);
                      if (!touched.name) setTouched((prev) => ({ ...prev, name: true }));
                    }}
                    required
                    placeholder="Enter your name"
                    error={showNameError ? 'Name is required.' : undefined}
                  />

                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={(value) => {
                      setEmail(value);
                      if (!touched.email) setTouched((prev) => ({ ...prev, email: true }));
                    }}
                    required
                    placeholder="Enter your email"
                    error={showEmailError ? 'Please enter a valid email address.' : undefined}
                  />

                  <Stack gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      Choose an avatar
                    </Text>
                    <Box
                      padding="var(--ggui-spacing-2, 8px)"
                      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                    >
                      <Stack direction="horizontal" wrap gap={8}>
                        {displayedAvatars.map((emoji) => {
                          const selected = avatar === emoji;
                          return (
                            <Button
                              key={emoji}
                              variant={selected ? 'primary' : 'outline'}
                              size="md"
                              aria-label={`Select avatar ${emoji}`}
                              aria-pressed={selected}
                              onPress={() => setAvatar(emoji)}
                            >
                              {emoji}
                            </Button>
                          );
                        })}
                      </Stack>
                    </Box>
                  </Stack>
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack gap={16}>
                  <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">
                    Preferences
                  </Heading>

                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={roleSelectOptions}
                    placeholder="Select your role"
                    required
                    error={!isStep2Valid ? 'Role is required to continue.' : undefined}
                  />

                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                    size="md"
                  />

                  <Toggle
                    label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                    size="md"
                  />
                </Stack>
              )}

              {currentStep === 3 && (
                <Stack gap={12}>
                  <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">
                    Review & Confirm
                  </Heading>

                  <Box
                    padding="var(--ggui-spacing-4, 16px)"
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                  >
                    <Stack gap={10}>
                      <Stack direction="horizontal" justify="between" wrap>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Name
                        </Text>
                        <Text color="var(--ggui-color-onSurface, #18181b)">{name || '-'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" wrap>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Email
                        </Text>
                        <Text color="var(--ggui-color-onSurface, #18181b)">{email || '-'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" wrap>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Avatar
                        </Text>
                        <Text color="var(--ggui-color-onSurface, #18181b)">{avatar || '-'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" wrap>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Role
                        </Text>
                        <Text color="var(--ggui-color-onSurface, #18181b)">{role || '-'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" wrap>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Email notifications
                        </Text>
                        <Text color="var(--ggui-color-onSurface, #18181b)">
                          {emailNotifications ? 'On' : 'Off'}
                        </Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" wrap>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Theme
                        </Text>
                        <Text color="var(--ggui-color-onSurface, #18181b)">
                          {theme === 'dark' ? 'Dark' : 'Light'}
                        </Text>
                      </Stack>
                    </Stack>
                  </Box>
                </Stack>
              )}
            </Stack>
          </Box>

          <Divider color="var(--ggui-color-outline, #d4d4d8)" margin={0} />

          <Stack direction="horizontal" justify="between" align="center" wrap gap={8}>
            <Button
              variant="ghost"
              onPress={handleBack}
              disabled={currentStep === 1}
            >
              {currentStep === 3 ? 'Go Back' : 'Back'}
            </Button>

            {currentStep < 3 ? (
              <Button
                variant="primary"
                onPress={handleNext}
                disabled={!canGoNext}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onPress={handleComplete}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
      {/* __GGUI_META__={"category":"Forms","description":"A reusable 3-step onboarding wizard with validation, progress indicator, animated step transitions, and final completion callback payload."} */}
    </Container>
  );
}

