            style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', minWidth: 120 }}
          >
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {String(windSpeed)}
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Stack direction="vertical" gap={8} aria-label="5-day forecast">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Forecast
          </Text>
          <Stack direction="horizontal" gap={8} justify="between" align="stretch">
            {normalizedForecast.map((item, index) => {
              const day = item.day ?? '—';
              const icon = item.icon ?? '•';
              const high = typeof item.high === 'number' ? `${item.high}°` : '';
              const low = typeof item.low === 'number' ? `${item.low}°` : '';

              return (
                <Box
                  key={`${item.day ?? 'day'}-${index}`}
                  padding="var(--ggui-spacing-2, 8px)"
                  background="var(--ggui-color-surface, #fafafa)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  style={{
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    flex: 1,
                    minWidth: 0,
                  }}
                  aria-label={`${day} forecast`}
                >
                  <Stack direction="vertical" gap={4} align="center">
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                    >
                      {day}
                    </Text>
                    <Text as="span" size="xl" aria-hidden="true">
                      {icon}
                    </Text>
                    <Stack direction="vertical" gap={2} align="center">
                      {high ? (
                        <Text
                          variant="bodySmall"
                          weight="semibold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {high}
                          {normalizedUnit}
                        </Text>
                      ) : null}
                      {low ? (
                        <Text
                          variant="bodySmall"
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        >
                          {low}
                          {normalizedUnit}
                        </Text>
                      ) : null}
                    </Stack>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Button,
  Card,
  Checkbox,
  Input,
  Progress,
  RadioGroup,
  Stack,
  Text,
  TextArea,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: Submit Survey */
  submit?: (answers: {
    name: string;
    email: string;
    satisfaction: { value: string; label: string };
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
  /** Optional UI text defaults */
  title?: string;
  stepTitles?: [string, string, string, string, string];
  submitButtonLabel?: string;
}

export default function GeneratedComponent({
  featureOptions = ['Ease of Use', 'Performance', 'Integrations'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  submit,
  title = 'Customer Survey',
  stepTitles = ['Basic Info', 'Satisfaction', 'Feature Interests', 'Comments', 'Review'],
  submitButtonLabel = 'Submit Survey',
}: Props) {
  const [step, setStep] = useState(1);
  const totalSteps = 5;

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });
  const [submitting, setSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && !name.trim() ? 'Name is required' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required'
      : touched.email && !emailValid
      ? 'Please enter a valid email address'
      : '';

  const stepValid = useMemo(() => {
    if (step === 1) return !!name.trim() && !!email.trim() && emailValid;
    if (step === 2) return !!satisfaction;
    return true;
  }, [step, name, email, emailValid, satisfaction]);

  const canGoBack = step > 1;
  const canGoNext = step < totalSteps && stepValid;

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) => (checked ? [...prev, feature] : prev.filter((f) => f !== feature)));
  };

  const satisfactionOptions = satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const handleNext = () => {
    if (step === 1) {
      setTouched({ name: true, email: true });
    }
    if (!stepValid) return;
    setStep((s) => Math.min(totalSteps, s + 1));
  };

  const handleBack = () => setStep((s) => Math.max(1, s - 1));

  const handleSubmit = async () => {
    if (!submit) return;
    setSubmitting(true);
    setFeedback(null);
    try {
      const selectedLabel = satisfactionLabels[Number(satisfaction) - 1] || '';
      await submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: { value: satisfaction, label: selectedLabel },
        featureInterests,
        comments: comments.trim(),
      });
      setFeedback({ type: 'success', message: 'Survey submitted successfully.' });
    } catch (e) {
      setFeedback({ type: 'error', message: 'Failed to submit survey. Please try again.' });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          {title}
        </Text>

        <Stack gap={6}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {step} of {totalSteps} — {stepTitles[step - 1]}
          </Text>
          <Progress value={step} max={totalSteps} size="md" />
        </Stack>

        {feedback && (
          <Alert variant={feedback.type === 'success' ? 'success' : 'error'} title={feedback.type === 'success' ? 'Success' : 'Error'}>
            {feedback.message}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              error={nameError}
              placeholder="Enter your full name"
              onBlur={() => setTouched((t) => ({ ...t, name: true }))}
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError}
              placeholder="you@example.com"
              onBlur={() => setTouched((t) => ({ ...t, email: true }))}
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="How satisfied are you overall?"
            value={satisfaction}
            onChange={setSatisfaction}
            options={satisfactionOptions}
            direction="vertical"
            error={!satisfaction ? 'Please select a satisfaction rating' : ''}
          />
        )}

        {step === 3 && (
          <Stack gap={10}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Which features are you interested in?
            </Text>
            {featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={featureInterests.includes(feature)}
                onChange={(checked) => handleFeatureToggle(feature, checked)}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={8}>
            <TextArea
              label="Additional comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              placeholder="Share any additional thoughts..."
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={10}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Review your answers
            </Text>
            <Card
              padding={16}
              shadow="none"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
              }}
            >
              <Stack gap={8}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Name:</strong> {name || '-'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Email:</strong> {email || '-'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Satisfaction:</strong> {satisfactionLabels[Number(satisfaction) - 1] || '-'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Feature Interests:</strong> {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Comments:</strong> {comments.trim() || 'No comments'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" align="center">
          <Button variant="ghost" onClick={handleBack} disabled={!canGoBack || submitting}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button variant="primary" onClick={handleNext} disabled={!canGoNext || submitting}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={submitting} disabled={submitting}>
              {submitButtonLabel}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-primary-600, #0284c7)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-success-600, #16a34a)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

export default function GeneratedComponent({ elements = [] }: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return undefined;
    return elements.find((e) => e.atomicNumber === selectedAtomicNumber);
  }, [elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((e) => set.add((e.category ?? 'unknown').toLowerCase()));
    return Array.from(set);
  }, [elements]);

  return (
    <Card
      padding={16}
      shadow="sm"
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Search Elements
          </Text>
          <Input
            value={query}
            onChange={setQuery}
            type="search"
            placeholder="Search by name or symbol"
            aria-label="Search elements by name or symbol"
          />
        </Stack>

        <Card
          padding={12}
          radius="md"
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table of elements"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              overflowX: 'auto',
              paddingBottom: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            {filteredElements.map((el) => {
              const categoryKey = (el.category ?? 'unknown').toLowerCase();
              const bg = categoryColorMap[categoryKey] ?? categoryColorMap.unknown;
              const atomicNumber = el.atomicNumber ?? 0;
              const symbol = el.symbol ?? '';
              const isSelected = selectedAtomicNumber === atomicNumber;

              return (
                <Button
                  key={`${atomicNumber}-${symbol}`}
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedAtomicNumber(atomicNumber)}
                  aria-label={`Element ${el.name ?? 'Unknown'} (${symbol}) atomic number ${atomicNumber}`}
                  style={{
                    gridColumn: el.col ?? 'auto',
                    gridRow: el.row ?? 'auto',
                    minHeight: 64,
                    padding: 6,
                    border: isSelected
                      ? '2px solid var(--ggui-color-onSurface, #18181b)'
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    background: bg,
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    position: 'relative',
                    transition:
                      'transform 120ms ease, box-shadow 120ms ease, border-color 120ms ease',
                    boxShadow: isSelected
                      ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
                      : 'none',
                  }}
                >
                  <Text
                    as="span"
                    variant="caption"
                    style={{
                      position: 'absolute',
                      top: 4,
                      left: 6,
                      color: 'var(--ggui-color-onSurface, #18181b)',
                    }}
                  >
                    {atomicNumber}
                  </Text>
                  <Text as="span" size="xl" weight="bold" align="center">
                    {symbol}
                  </Text>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={16}
          radius="md"
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label">Element Details</Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="body">
                  <strong>Name:</strong> {selectedElement.name ?? '—'}
                </Text>
                <Text variant="body">
                  <strong>Symbol:</strong> {selectedElement.symbol ?? '—'}
                </Text>
                <Text variant="body">
                  <strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}
                </Text>
                <Text variant="body">
                  <strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}
                </Text>
                <Text variant="body">
                  <strong>Category:</strong> {selectedElement.category ?? '—'}
                </Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={16}
          radius="md"
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label">Legend</Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((cat) => {
                const color = categoryColorMap[cat] ?? categoryColorMap.unknown;
                return (
                  <Stack
                    key={cat}
                    direction="horizontal"
                    align="center"
                    gap={6}
                    style={{
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      padding: '4px 10px',
                      background: 'var(--ggui-color-surface, #fafafa)',
                    }}
                  >
                    <span
                      aria-hidden="true"
                      style={{
                        width: 10,
                        height: 10,
                        borderRadius: '50%',
                        background: color,
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      }}
                    />
                    <Text as="span" variant="caption" style={{ textTransform: 'capitalize' }}>
                      {cat}
                    </Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract: send outgoing message payload */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
  /** Interaction Contract alias */
  onSubmit?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = '',
    currentUser = '',
    participantCount,
    messages = [],
    sendMessage,
    onSubmit,
  } = props;

  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const listRef = useRef<HTMLDivElement>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];
    allMessages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && (last.sender || '') === (msg.sender || '')) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const custom = event as CustomEvent<{ message?: { sender?: string; text?: string; timestamp?: string } }>;
      const incoming = custom.detail?.message;
      if (incoming && (incoming.text || incoming.sender || incoming.timestamp)) {
        setStreamMessages((prev) => [...prev, incoming]);
      }
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  const formatTimestamp = (iso?: string) => {
    if (!iso) return '';
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    onSubmit?.(payload);
    setDraft('');
  };

  return (
    <Card
      shadow="sm"
      border
      radius="lg"
      padding={0}
    >
      <Stack gap={0}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          {typeof participantCount === 'number' ? (
            <Badge variant="primary" size="sm">
              {participantCount}
            </Badge>
          ) : null}
        </Stack>

        <Stack
          gap={12}
          style={{
            height: '360px',
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          ref={listRef}
          aria-label="Message list"
        >
          {groupedMessages.map((group, gIdx) => {
            const isOwn = (group.sender || '') === currentUser;
            return (
              <Stack
                key={`${group.sender || 'unknown'}-${gIdx}`}
                align={isOwn ? 'end' : 'start'}
                gap={6}
              >
                {group.items.map((msg, mIdx) => (
                  <Stack
                    key={`${msg.timestamp || 't'}-${mIdx}-${msg.text || ''}`}
                    gap={4}
                    style={{
                      maxWidth: '80%',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      background: isOwn
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: isOwn
                        ? 'var(--ggui-color-surface, #fafafa)'
                        : 'var(--ggui-color-onSurface, #18181b)',
                      border: `1px solid ${
                        isOwn
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-outlineVariant, #e4e4e7)'
                      }`,
                      transition: 'background-color 200ms ease-in-out, border-color 200ms ease-in-out',
                    }}
                  >
                    <Text
                      variant="caption"
                      weight="medium"
                      color={
                        isOwn
                          ? 'var(--ggui-color-surface, #fafafa)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                    >
                      {msg.sender || ''}
                    </Text>
                    <Text
                      variant="body"
                      color={
                        isOwn
                          ? 'var(--ggui-color-surface, #fafafa)'
                          : 'var(--ggui-color-onSurface, #18181b)'
                      }
                    >
                      {msg.text || ''}
                    </Text>
                    <Text
                      variant="caption"
                      color={
                        isOwn
                          ? 'var(--ggui-color-surface, #fafafa)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                      align="right"
                    >
                      {formatTimestamp(msg.timestamp)}
                    </Text>
                  </Stack>
                ))}
              </Stack>
            );
          })}
        </Stack>

        <Stack
          direction="horizontal"
          align="end"
          gap={8}
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack style={{ flex: 1 }}>
            <Input
              label="Compose message"
              placeholder={title}
              value={draft}
              onChange={setDraft}
              aria-label="Message input"
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </Stack>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

type StreamPayload = Partial<Props> & {
  status?: 'connecting' | 'connected' | 'loading' | 'idle';
};

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(props.stocks ?? []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [streamStatus, setStreamStatus] = useState<'connecting' | 'connected' | 'loading' | 'idle'>('connecting');

  useEffect(() => {
    setLiveStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    setLiveLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<StreamPayload>;
      const payload = customEvent.detail ?? {};

      if (payload.status) {
        setStreamStatus(payload.status);
      } else {
        setStreamStatus('connected');
      }

      if (payload.stocks) {
        setLiveStocks(payload.stocks);
      }
      if (payload.lastUpdated) {
        setLiveLastUpdated(payload.lastUpdated);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    const connectTimer = window.setTimeout(() => {
      setStreamStatus((prev) => (prev === 'connecting' ? 'loading' : prev));
    }, 900);

    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData);
      window.clearTimeout(connectTimer);
    };
  }, []);

  const formattedLastUpdated = useMemo(() => {
    if (!liveLastUpdated) return 'N/A';
    const d = new Date(liveLastUpdated);
    if (Number.isNaN(d.getTime())) return liveLastUpdated;
    return d.toLocaleString();
  }, [liveLastUpdated]);

  const isWaitingForData = streamStatus === 'connecting' || streamStatus === 'loading';

  return (
    <Stack
      gap={16}
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        wrap
        style={{
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          paddingBottom: 'var(--ggui-spacing-2, 8px)',
        }}
      >
        <Text
          as="div"
          size="2xl"
          weight="bold"
          color="var(--ggui-color-onSurface, #18181b)"
          aria-label="Market Watch title"
        >
          Market Watch
        </Text>
        <Stack direction="horizontal" align="center" gap={8}>
          {isWaitingForData && <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />}
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" aria-live="polite">
            {isWaitingForData ? 'Connecting live feed…' : 'Live feed connected'}
          </Text>
        </Stack>
      </Stack>

      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        Last Updated: {formattedLastUpdated}
      </Text>

      {isWaitingForData && liveStocks.length === 0 ? (
        <Card
          padding={20}
          border
          radius="lg"
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack direction="horizontal" align="center" gap={10}>
            <Spinner size={20} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Loading stock prices…
            </Text>
          </Stack>
        </Card>
      ) : (
        <Stack
          gap={12}
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
          }}
        >
          {liveStocks.map((stock, idx) => {
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const isPositive = change >= 0;
            const trendColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const arrow = isPositive ? '▲' : '▼';

            return (
              <Card
                key={`${stock.symbol ?? 'stock'}-${idx}`}
                padding={16}
                border
                radius="lg"
                shadow="sm"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: trendColor,
                  transition: 'transform 200ms ease, box-shadow 200ms ease',
                }}
                aria-label={`Stock card ${stock.symbol ?? 'Unknown symbol'}`}
              >
                <Stack gap={6}>
                  <Text
                    as="div"
                    size="3xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                    truncate
                  >
                    {stock.symbol ?? '—'}
                  </Text>

                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                    {stock.name ?? 'Unknown Company'}
                  </Text>

                  <Text as="div" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    ${(stock.price ?? 0).toFixed(2)}
                  </Text>

                  <Text variant="bodySmall" color={trendColor}>
                    {change >= 0 ? '+' : ''}
                    {change.toFixed(2)}
                  </Text>

                  <Text variant="label" color={trendColor} aria-label="Stock change percentage">
                    {arrow} {changePercent >= 0 ? '+' : ''}
                    {changePercent.toFixed(2)}%
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Stack>
      )}
    </Stack>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Progress,
  Select,
  Toggle,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions[0] ?? ''
  );
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const emailValid = useMemo(() => emailRegex.test(email.trim()), [email]);
  const step1Valid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canNext = currentStep === 1 ? step1Valid : currentStep === 2 ? step2Valid : true;

  const goNext = () => {
    if (!canNext) return;
    setCurrentStep((s) => Math.min(3, s + 1));
  };

  const goBack = () => setCurrentStep((s) => Math.max(1, s - 1));

  const handleComplete = () => {
    const payload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    props.complete?.(payload);
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          color: 'var(--ggui-color-onSurface, #18181b)',
          maxWidth: 680,
          margin: '0 auto',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {currentStep} / 3
            </Text>
            <Progress value={currentStep} max={3} size="md" />
          </Stack>

          <Stack
            gap={16}
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            }}
          >
            {currentStep === 1 && (
              <Stack gap={14}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={name.trim().length === 0 ? 'Name is required' : undefined}
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="Enter your email"
                  error={email.length > 0 && !emailValid ? 'Please enter a valid email address' : undefined}
                />

                <Stack gap={8}>
                  <Text as="label" variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Avatar Selection
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {props.avatarOptions.map((option) => {
                      const selected = avatar === option;
                      return (
                        <Button
                          key={option}
                          variant={selected ? 'primary' : 'secondary'}
                          size="md"
                          aria-label={`Select avatar ${option}`}
                          onClick={() => setAvatar(option)}
                        >
                          {option}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={14}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select role"
                  required
                  options={props.roleOptions.map((r) => ({ label: r, value: r }))}
                  error={role.trim().length === 0 ? 'Role is required' : undefined}
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />

                <Toggle
                  label={`Theme preference: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>

                <Card
                  padding={16}
                  shadow="none"
                  radius="md"
                  border
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={8}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Name:</strong> {name || '-'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Email:</strong> {email || '-'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Avatar:</strong> {avatar || '-'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Role:</strong> {role || '-'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Theme:</strong> {theme}
                    </Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>

          <Stack direction="horizontal" justify="between" gap={8}>
            <Button variant="ghost" onClick={goBack} disabled={currentStep === 1}>
              Back
            </Button>

            {currentStep < 3 ? (
              <Button variant="primary" onClick={goNext} disabled={!canNext}>
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="outline" onClick={goBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
      {/* __GGUI_META__ */}
      <Text as="span" style={{ display: 'none' }}>
        {`{"category":"form","description":"Three-step onboarding wizard with validation, progress indicator, navigation, review, and completion callback."}`}
      </Text>
    </>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const resolveConditionIcon = (value: string): string => {
  const normalized = value.toLowerCase();

  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
  if (
    normalized.includes('rain') ||
    normalized.includes('drizzle') ||
    normalized.includes('shower')
  ) {
    return '🌧️';
  }
  if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('ice'))
    return '❄️';
  if (normalized.includes('wind') || normalized.includes('breeze')) return '💨';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze'))
    return '🌫️';

  return '🌤️';
};

const formatTemp = (value: number | undefined, unit: string): string | null =>
  typeof value === 'number' ? `${value}°${unit}` : null;

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props) {
  const currentIcon = resolveConditionIcon(condition);

  return (
    <Card
      padding={24}
      shadow="md"
      radius="xl"
      border
      aria-label={`${city} weather: ${temperature} degrees ${unit}, ${condition}`}
    >
      <Stack direction="vertical" gap={16} align="stretch">
        <Stack direction="horizontal" justify="between" align="start" gap={16} wrap>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="overline"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              truncate
              as="div"
            >
              {city}
            </Text>
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              {temperature}°{unit}
            </Heading>
            <Text
              variant="bodyLarge"
              weight="medium"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>

          <Box
            padding={16}
            borderRadius="var(--ggui-shape-radius-full, 9999px)"
            background="var(--ggui-color-container, #ede9fe)"
          >
            <Text
              as="span"
              size="4xl"
              align="center"
              color="var(--ggui-color-onContainer, #4c1d95)"
              aria-hidden="true"
            >
              {currentIcon}
            </Text>
          </Box>
        </Stack>

        <Box
          padding={16}
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        >
          <Stack direction="horizontal" justify="between" align="center" gap={16} wrap>
            <Stack direction="vertical" gap={4} align="start">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>

            <Divider
              orientation="vertical"
              margin={0}
              color="var(--ggui-color-outlineVariant, #e4e4e7)"
            />

            <Stack direction="vertical" gap={4} align="start">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed}
              </Text>
            </Stack>
          </Stack>
        </Box>

        <Divider
          orientation="horizontal"
          margin={0}
          color="var(--ggui-color-outlineVariant, #e4e4e7)"
        />

        <Stack direction="vertical" gap={12}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Forecast
          </Text>

          <Stack direction="horizontal" gap={8} justify="between" align="stretch" wrap>
            {forecast.map((item, index) => {
              const day = item.day ?? '';
              const icon = item.icon ?? currentIcon;
              const high = formatTemp(item.high, unit);
              const low = formatTemp(item.low, unit);

              return (
                <Box
                  key={item.day ? `${item.day}-${index}` : `forecast-${index}`}
                  paddingY={12}
                  paddingX={8}
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                >
                  <Stack direction="vertical" gap={4} align="center">
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                    >
                      {day}
                    </Text>
                    <Text
                      size="2xl"
                      color="var(--ggui-color-onSurface, #18181b)"
                      aria-hidden="true"
                      as="span"
                    >
                      {icon}
                    </Text>
                    {high ? (
                      <Text
                        variant="bodySmall"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {high}
                      </Text>
                    ) : null}
                    {low ? (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {low}
                      </Text>
                    ) : null}
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Survey — called with all collected answers as a structured object */
  onSubmit?: (payload: {
    name: string;
    email: string;
    satisfactionRating: string;
    satisfactionLabel: string;
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

const defaultProps: Props = {
  featureOptions: ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels: ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit: async () => {},
};

export default function GeneratedComponent(incomingProps: Props) {
  const props = { ...defaultProps, ...incomingProps };

  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [submitting, setSubmitting] = useState(false);
  const [submitState, setSubmitState] = useState<'idle' | 'success' | 'error'>('idle');
  const [submitError, setSubmitError] = useState('');

  const totalSteps = 5;

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailValid
      ? 'Please enter a valid email address.'
      : '';
  const satisfactionError =
    touched.satisfaction && !satisfactionRating ? 'Please select a satisfaction rating.' : '';

  const canNext =
    (step === 1 && !!name.trim() && !!email.trim() && emailValid) ||
    (step === 2 && !!satisfactionRating) ||
    step === 3 ||
    step === 4;

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  };

  const goNext = () => {
    if (step === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      if (!name.trim() || !email.trim() || !emailValid) return;
    }
    if (step === 2) {
      setTouched((prev) => ({ ...prev, satisfaction: true }));
      if (!satisfactionRating) return;
    }
    setStep((s) => Math.min(totalSteps, s + 1));
  };

  const goBack = () => setStep((s) => Math.max(1, s - 1));

  const handleSubmit = async () => {
    setSubmitState('idle');
    setSubmitError('');
    setSubmitting(true);
    try {
      const ratingIndex = Number(satisfactionRating) - 1;
      await props.onSubmit?.({
        name: name.trim(),
        email: email.trim(),
        satisfactionRating,
        satisfactionLabel: props.satisfactionLabels[ratingIndex] || '',
        featureInterests,
        comments: comments.trim(),
      });
      setSubmitState('success');
    } catch (err) {
      setSubmitState('error');
      setSubmitError(err instanceof Error ? err.message : 'Submission failed. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={6}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={step} max={totalSteps} size="md" />
        </Stack>

        {submitState === 'success' && (
          <Alert variant="success" title="Survey submitted">
            Thank you for your feedback.
          </Alert>
        )}
        {submitState === 'error' && (
          <Alert variant="error" title="Submission error">
            {submitError}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Basic information
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              error={nameError}
              placeholder="Enter your name"
              aria-label="Name"
              onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError}
              placeholder="Enter your email"
              aria-label="Email"
              onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Satisfaction rating
            </Text>
            <RadioGroup
              label="How satisfied are you?"
              value={satisfactionRating}
              onChange={setSatisfactionRating}
              error={satisfactionError}
              options={props.satisfactionLabels.map((label, index) => ({
                value: String(index + 1),
                label,
              }))}
              direction="vertical"
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Feature interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all that apply.
            </Text>
            <Stack gap={8}>
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={featureInterests.includes(feature)}
                  onChange={(checked) => toggleFeature(feature, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Additional comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              maxLength={500}
              showCount
              rows={6}
              placeholder="Share any additional feedback..."
              aria-label="Comments"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Review your answers
            </Text>
            <Card
              padding={16}
              shadow="none"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {name || '-'}</Text>
                <Text variant="body"><strong>Email:</strong> {email || '-'}</Text>
                <Text variant="body">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfactionRating
                    ? props.satisfactionLabels[Number(satisfactionRating) - 1] || '-'
                    : '-'}
                </Text>
                <Text variant="body">
                  <strong>Feature interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="body">
                  <strong>Comments:</strong> {comments.trim() || 'No comments provided'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={12}>
          <Button variant="secondary" onClick={goBack} disabled={step === 1 || submitting}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button variant="primary" onClick={goNext} disabled={!canNext || submitting}>
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              loading={submitting}
              disabled={submitting}
              aria-label="Submit Survey"
            >
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const defaultElements: Props['elements'] = [];

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-primary-600, #0284c7)',
  'transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  'post-transition metal': 'var(--ggui-color-neutral-500, #6b7280)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

const getCategoryColor = (category?: string) =>
  categoryColorMap[(category || 'unknown').toLowerCase()] || 'var(--ggui-color-neutral-400, #9ca3af)';

export default function GeneratedComponent({ elements = defaultElements }: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(
    elements.find((e) => e.atomicNumber !== undefined)?.atomicNumber
  );

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  const selectedElement = useMemo(
    () => elements.find((e) => e.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
    const unique = Array.from(
      new Set(elements.map((e) => (e.category || 'Unknown').trim()).filter((c) => c.length > 0))
    );
    return unique.sort((a, b) => a.localeCompare(b));
  }, [elements]);

  return (
    <Card
      padding={16}
      border
      shadow="sm"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack gap={16}>
        <Input
          label="Search elements"
          type="search"
          placeholder="Search by name or symbol"
          value={query}
          onChange={setQuery}
          aria-label="Search elements by name or symbol"
        />

        <Card
          padding={12}
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            {filteredElements.map((el) => {
              const color = getCategoryColor(el.category);
              const atomicNumber = el.atomicNumber ?? 0;
              const symbol = el.symbol || '';
              const name = el.name || 'Unknown';

              return (
                <button
                  key={`${atomicNumber}-${symbol}-${name}`}
                  type="button"
                  role="gridcell"
                  aria-label={`${name} (${symbol}) atomic number ${atomicNumber}`}
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                  style={{
                    gridColumn: el.col ? `${el.col}` : undefined,
                    gridRow: el.row ? `${el.row}` : undefined,
                    minHeight: '64px',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                    background: 'var(--ggui-color-surface, #fafafa)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    cursor: 'pointer',
                    position: 'relative',
                    transition: 'transform 100ms ease, box-shadow 200ms ease, border-color 200ms ease',
                    boxShadow:
                      selectedAtomicNumber === el.atomicNumber
                        ? `0 0 0 2px ${color}`
                        : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: '4px',
                      left: '6px',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    }}
                  >
                    {el.atomicNumber ?? ''}
                  </span>
                  <span
                    style={{
                      display: 'block',
                      textAlign: 'center',
                      fontSize: 'var(--ggui-font-size-xl, 20px)',
                      fontWeight: 'var(--ggui-font-weight-bold, 700)',
                      lineHeight: 1.2,
                      color,
                    }}
                  >
                    {el.symbol ?? ''}
                  </span>
                </button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={12}
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label">Element Details</Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="body">
                  <strong>Name:</strong> {selectedElement.name ?? '—'}
                </Text>
                <Text variant="body">
                  <strong>Symbol:</strong> {selectedElement.symbol ?? '—'}
                </Text>
                <Text variant="body">
                  <strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}
                </Text>
                <Text variant="body">
                  <strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}
                </Text>
                <Text variant="body">
                  <strong>Category:</strong> {selectedElement.category ?? '—'}
                </Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={12}
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label">Legend</Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((category) => (
                <Badge
                  key={category}
                  variant="default"
                  size="md"
                  pill
                  style={{
                    background: getCategoryColor(category),
                    color: 'var(--ggui-color-surface, #fafafa)',
                  }}
                >
                  {category}
                </Badge>
              ))}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Button, Card, Input, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: send callback */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title,
  currentUser,
  participantCount,
  messages,
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState('');
  const listRef = useRef<HTMLDivElement | null>(null);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    messages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [messages]);

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages.length]);

  useEffect(() => {
    const handler = () => {
      scrollToBottom();
    };
    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const handleSubmit = () => {
    const text = draft.trim();
    if (!text) return;
    sendMessage({ text, timestamp: new Date().toISOString() });
    setDraft('');
  };

  return (
    <Card
      padding={0}
      radius="lg"
      border
      shadow="sm"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        minHeight: '420px',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        }}
      >
        <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          {title}
        </Text>
        {typeof participantCount === 'number' && (
          <Badge variant="primary" size="sm" aria-label={`Participants: ${participantCount}`}>
            {participantCount}
          </Badge>
        )}
      </Stack>

      <Stack
        ref={listRef}
        gap={12}
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          background: 'var(--ggui-color-surface, #fafafa)',
        }}
        aria-label="Message list"
      >
        {groupedMessages.map((group, groupIndex) => {
          const isCurrentUser = (group.sender || '') === currentUser;
          return (
            <Stack
              key={`${group.sender || 'unknown'}-${groupIndex}`}
              align={isCurrentUser ? 'end' : 'start'}
              gap={6}
              style={{ width: '100%' }}
            >
              {group.items.map((message, messageIndex) => (
                <Stack
                  key={`${groupIndex}-${messageIndex}-${message.timestamp || ''}-${message.text || ''}`}
                  gap={4}
                  style={{
                    maxWidth: '80%',
                    padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    background: isCurrentUser
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    color: isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                    border: isCurrentUser ? 'none' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  }}
                >
                  <Text
                    variant="caption"
                    weight="medium"
                    color={isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                  >
                    {message.sender || ''}
                  </Text>
                  <Text
                    variant="bodySmall"
                    color={isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                  >
                    {message.text || ''}
                  </Text>
                  <Text
                    variant="caption"
                    color={isCurrentUser ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                    align="right"
                  >
                    {formatTime(message.timestamp)}
                  </Text>
                </Stack>
              ))}
            </Stack>
          );
        })}
      </Stack>

      <Stack
        direction="horizontal"
        gap={8}
        align="end"
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        }}
      >
        <div style={{ flex: 1 }}>
          <Input
            label="Message"
            placeholder="Type a message..."
            value={draft}
            onChange={setDraft}
            aria-label="Compose message"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleSubmit();
              }
            }}
          />
        </div>
        <Button
          variant="primary"
          size="md"
          onClick={handleSubmit}
          disabled={!draft.trim()}
          aria-label="Send message"
        >
          Send
        </Button>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Heading, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = '',
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string>(lastUpdated);
  const [connectionState, setConnectionState] = useState<'connecting' | 'connected' | 'idle'>('connecting');

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    let connectedTimer: number | undefined;
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const detail = customEvent.detail || {};
      if (detail.stocks) setLiveStocks(detail.stocks);
      if (typeof detail.lastUpdated === 'string') setLiveLastUpdated(detail.lastUpdated);
      setConnectionState('connected');
      if (connectedTimer) window.clearTimeout(connectedTimer);
      connectedTimer = window.setTimeout(() => setConnectionState('idle'), 4000);
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData);
      if (connectedTimer) window.clearTimeout(connectedTimer);
    };
  }, []);

  const formattedTimestamp = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const d = new Date(liveLastUpdated);
    return Number.isNaN(d.getTime()) ? liveLastUpdated : d.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Stack
      gap="var(--ggui-spacing-4, 16px)"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Card
        border
        shadow="sm"
        radius="lg"
        padding="var(--ggui-spacing-4, 16px)"
        style={{ borderColor: 'var(--ggui-color-outline, #d4d4d8)' }}
      >
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Heading>
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            {connectionState === 'connecting' && <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />}
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {connectionState === 'connecting'
                ? 'Connecting live feed…'
                : connectionState === 'connected'
                ? 'Live updates connected'
                : 'Live feed idle'}
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formattedTimestamp}
            </Text>
          </Stack>
        </Stack>
      </Card>

      <div
        role="list"
        aria-label="Stock ticker list"
        style={{
          display: 'grid',
          gap: 'var(--ggui-spacing-4, 16px)',
          gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
        }}
      >
        {liveStocks.map((stock, index) => {
          const change = stock.change ?? 0;
          const changePercent = stock.changePercent ?? 0;
          const isPositive = change >= 0;
          const trendColor = isPositive
            ? 'var(--ggui-color-success-600, #16a34a)'
            : 'var(--ggui-color-error-600, #dc2626)';
          const trendArrow = isPositive ? '▲' : '▼';

          return (
            <Card
              key={`${stock.symbol ?? 'stock'}-${index}`}
              border
              shadow="sm"
              radius="lg"
              padding="var(--ggui-spacing-4, 16px)"
              style={{
                borderColor: trendColor,
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                transition: 'border-color 200ms ease, box-shadow 200ms ease, transform 200ms ease',
              }}
              role="listitem"
              aria-label={`${stock.symbol ?? 'Unknown'} stock card`}
            >
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {stock.symbol ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {stock.name ?? 'Unknown Company'}
                </Text>
                <Text size="2xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {(stock.price ?? 0).toFixed(2)}
                </Text>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label" color={trendColor}>
                    {change >= 0 ? '+' : ''}
                    {change.toFixed(2)}
                  </Text>
                  <Text variant="label" color={trendColor} aria-label="Change percentage">
                    {trendArrow} {changePercent >= 0 ? '+' : ''}
                    {changePercent.toFixed(2)}%
                  </Text>
                </Stack>
              </Stack>
            </Card>
          );
        })}
      </div>
    </Stack>
  );
}

