    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState<number>(1);

  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? ''
  );

  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const step1Valid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);

  const handleNext = () => {
    if (step < 3 && canNext) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleComplete = () => {
    if (!step1Valid || !step2Valid) return;
    props.complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-live="polite"
            >
              Step {step} of 3
            </Text>
            <Progress value={step} max={3} size="md" />
          </Stack>

          <Stack
            gap={16}
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            }}
          >
            {step === 1 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={name.trim().length === 0 ? 'Name is required' : undefined}
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="Enter your email"
                  error={
                    email.trim().length === 0
                      ? 'Email is required'
                      : !emailValid
                      ? 'Please enter a valid email format'
                      : undefined
                  }
                />

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Avatar Selection
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {props.avatarOptions.map((option) => {
                      const isActive = avatar === option;
                      return (
                        <Button
                          key={option}
                          variant={isActive ? 'primary' : 'outline'}
                          size="md"
                          onClick={() => setAvatar(option)}
                          aria-label={`Select avatar ${option}`}
                        >
                          {option}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  required
                  placeholder="Select your role"
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  error={role.trim().length === 0 ? 'Role is required' : undefined}
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />

                <Toggle
                  label={`Theme preference: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>

                <Card
                  padding={16}
                  shadow="none"
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={8}>
                    <Text color="var(--ggui-color-onSurface, #18181b)"><Text as="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)"><Text as="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)"><Text as="span" weight="semibold">Avatar:</Text> {avatar || '—'}</Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)"><Text as="span" weight="semibold">Role:</Text> {role || '—'}</Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)">
                      <Text as="span" weight="semibold">Email Notifications:</Text>{' '}
                      {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)">
                      <Text as="span" weight="semibold">Theme:</Text> {theme}
                    </Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>

          <Stack direction="horizontal" justify="between" gap={8}>
            <Button
              variant="ghost"
              onClick={handleBack}
              disabled={step === 1}
              aria-label="Go back to previous step"
            >
              Back
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!canNext}
                aria-label="Go to next step"
              >
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="secondary" onClick={handleBack} aria-label="Go back to edit">
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete} aria-label="Complete setup">
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
      {/* __GGUI_META__ */}
      {/* {"category":"form","description":"A 3-step onboarding wizard with profile setup, preferences, validation, progress indicator, review screen, and completion callback."} */}
    </>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Helper to get a generic emoji if one isn't provided for the condition
 */
function getWeatherEmoji(condition: string): string {
  const c = (condition || '').toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return '☀️';
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
  if (c.includes('thunder') || c.includes('storm')) return '⛈️';
  if (c.includes('snow')) return '❄️';
  if (c.includes('mist') || c.includes('fog')) return '🌫️';
  return '⛅';
}

/**
 * WeatherCard - A comprehensive weather display component
 * Implemented based on senior architect design specification.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  const displayUnit = `°${unit}`;

  return (
    <Card shadow="md" radius="xl" padding={24} border={true}>
      <Stack gap={20}>
        {/* Header: City and Unit */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={2}>
            <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">
              CURRENT WEATHER
            </Text>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
          </Stack>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {unit === 'C' ? 'Celsius' : 'Fahrenheit'}
          </Text>
        </Stack>

        {/* Main Temperature and Icon */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack direction="horizontal" align="start" gap={2}>
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
              as="span"
            >
              {Math.round(temperature)}
            </Text>
            <Text
              size="2xl"
              weight="semibold"
              color="var(--ggui-color-neutral-500, #6b7280)"
              as="span"
              style={{ marginTop: '8px' }}
            >
              {displayUnit}
            </Text>
          </Stack>
          <Stack align="end" gap={0}>
            {/* Using span for emojis as role is not supported in Text primitive directly */}
            <span style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }} role="img" aria-label={condition}>
              {getWeatherEmoji(condition)}
            </span>
            <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Details Strip */}
        <Box
          paddingX={16}
          paddingY={12}
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="horizontal" justify="between">
            <Stack direction="horizontal" gap={8} align="center">
              <span role="img" aria-label="Humidity">💧</span>
              <Stack gap={0}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
              </Stack>
            </Stack>
            <Divider orientation="vertical" margin={12} color="var(--ggui-color-outline, #d4d4d8)" />
            <Stack direction="horizontal" gap={8} align="center">
              <span role="img" aria-label="Wind speed">💨</span>
              <Stack gap={0}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind
                </Text>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{windSpeed} {unit === 'C' ? 'km/h' : 'mph'}</Text>
              </Stack>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast */}
        <Stack direction="horizontal" justify="between" align="center">
          {(forecast || []).slice(0, 5).map((item, idx) => (
            <Stack key={idx} align="center" gap={4}>
              <Text
                variant="caption"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {item.day}
              </Text>
              <span style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }} role="img" aria-label="Forecast condition">
                {item.icon || '☀️'}
              </span>
              <Stack gap={0} align="center">
                <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-neutral-400, #9ca3af)">
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Progress,
  RadioGroup,
  Checkbox,
  Divider,
  Spacer,
  Box,
  Container,
} from '@ggui-ai/design/primitives';
import { FormField } from '@ggui-ai/design/components';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called with all collected answers as a structured object */
  onSubmit?: (data: Record<string, any>) => void;
}

export default function GeneratedComponent({
  featureOptions = ['Feature A', 'Feature B'],
  satisfactionLabels = ['Unsatisfied', 'Neutral', 'Satisfied'],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [answers, setAnswers] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: '',
  });

  const validateEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const isStepValid = useMemo(() => {
    if (step === 1) return answers.name.trim() !== '' && validateEmail(answers.email);
    if (step === 2) return answers.satisfaction !== '';
    return true;
  }, [step, answers]);

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) await onSubmit(answers);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-12) var(--ggui-spacing-4)">
      <Card padding={32} shadow="md" radius="xl" border={true}>
        <Stack gap={32}>
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="overline" color="var(--ggui-color-primary-600)">Step {step <= 4 ? step : 4} of 4</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{step > 4 ? 'Review' : `${Math.round(((step - 1) / 4) * 100)}%`}</Text>
            </Stack>
            <Progress value={step > 4 ? 4 : step - 1} max={4} variant={step > 4 ? 'success' : 'default'} size="md" />
          </Stack>

          <Box>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={3}>Step 1: Contact</Heading>
                <FormField label="Full Name" required>
                  <Input label="Full Name" placeholder="e.g. Jane Doe" value={answers.name} onChange={(v) => setAnswers({ ...answers, name: v })} />
                </FormField>
                <FormField label="Email Address" required>
                  <Input label="Email Address" placeholder="e.g. jane@example.com" value={answers.email} onChange={(v) => setAnswers({ ...answers, email: v })} />
                </FormField>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={3}>Step 2: Rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={answers.satisfaction}
                  onChange={(v) => setAnswers({ ...answers, satisfaction: v })}
                  options={satisfactionLabels.map((l, i) => ({ label: l, value: (i + 1).toString() }))}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={3}>Step 3: Features</Heading>
                <Stack gap={12}>
                  {featureOptions.map((f) => (
                    <Checkbox
                      key={f}
                      label={f}
                      checked={answers.features.includes(f)}
                      onChange={(c) => setAnswers((p) => ({ ...p, features: c ? [...p.features, f] : p.features.filter((x) => x !== f) }))}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={24}>
                <Heading level={3}>Step 4: Feedback</Heading>
                <TextArea
                  label="Additional Feedback"
                  value={answers.comments}
                  onChange={(v) => setAnswers({ ...answers, comments: v })}
                  maxLength={500}
                  showCount
                  rows={4}
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap={24}>
                <Heading level={3}>Final Review</Heading>
                <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
                  <Stack gap={16}>
                    <Text variant="body"><strong>Name:</strong> {answers.name}</Text>
                    <Text variant="body"><strong>Email:</strong> {answers.email}</Text>
                    <Text variant="body"><strong>Rating:</strong> {satisfactionLabels[parseInt(answers.satisfaction) - 1]}</Text>
                    <Text variant="body"><strong>Features:</strong> {answers.features.join(', ') || 'None'}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" justify="between" align="center">
            {step > 1 && !isSubmitting ? (
              <Button variant="ghost" onClick={() => setStep(step - 1)}>Back</Button>
            ) : <Box />}

            {step < 5 ? (
              <Button variant="primary" onClick={() => setStep(step + 1)} disabled={!isStepValid}>
                {step === 4 ? 'Review' : 'Continue'}
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Container,
  Spacer,
} from '@ggui-ai/design/primitives';
import { SearchField, Tag } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps element categories to design system color tokens.
 * Provides distinct visual grouping using semantic theme colors.
 */
const getCategoryColor = (category?: string): string => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('noble gas')) return 'var(--ggui-color-primary-200, #bae6fd)';
  if (cat.includes('halogen') || cat.includes('diatomic nonmetal')) return 'var(--ggui-color-warning-100, #fef3c7)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-100, #fee2e2)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-200, #fde68a)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-primary-50, #f0f9ff)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-info-100, #cffafe)';
  if (cat.includes('actinide')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-info-200, #a5f3fc)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-100, #f3f4f6)';
  if (cat.includes('polyatomic nonmetal') || cat.includes('nonmetal')) return 'var(--ggui-color-success-200, #bbf7d0)';

  return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // Match logic for highlighting elements in the grid
  const isMatch = (el: ElementData) => {
    if (!searchTerm.trim()) return true;
    const lowerSearch = searchTerm.toLowerCase();
    return (
      el.name?.toLowerCase().includes(lowerSearch) ||
      el.symbol?.toLowerCase().includes(lowerSearch)
    );
  };

  // Extract unique categories to build the visual legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <Stack gap={24}>
        {/* Navigation & Header */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap={4}>
            <Heading level={2}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Click an element cell to view detailed properties.
            </Text>
          </Stack>
          <Box style={{ width: '320px' }}>
            <SearchField
              placeholder="Search elements..."
              value={searchTerm}
              onChange={setSearchTerm}
            />
          </Box>
        </Stack>

        {/* Category Legend */}
        <Stack direction="horizontal" gap={12} wrap align="center">
          {categories.map((cat) => (
            <Stack key={cat} direction="horizontal" align="center" gap={4}>
              <Box
                borderRadius="var(--ggui-shape-radius-sm, 4px)"
                background={getCategoryColor(cat)}
                style={{ 
                  width: 'var(--ggui-spacing-3, 12px)', 
                  height: 'var(--ggui-spacing-3, 12px)', 
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' 
                }}
              />
              <Text variant="caption" weight="medium">
                {cat}
              </Text>
            </Stack>
          ))}
        </Stack>

        {/* Element Grid Display */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            width: '100%',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-1, 4px)',
          }}
        >
          {elements.map((el) => {
            const active = isMatch(el);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const bgColor = getCategoryColor(el.category);

            return (
              <button
                key={el.atomicNumber}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridColumn: el.col,
                  gridRow: el.row,
                  aspectRatio: '1 / 1',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  cursor: 'pointer',
                  border: isSelected
                    ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                    : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  backgroundColor: bgColor,
                  opacity: active ? 1 : 0.2,
                  transition: 'all 200ms ease-in-out',
                  outline: 'none',
                  position: 'relative',
                  transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                  zIndex: isSelected ? 10 : 1,
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-lg)' : 'none',
                }}
                aria-label={`${el.name} (${el.symbol})`}
              >
                <Text
                  variant="caption"
                  size="xs"
                  weight="bold"
                  style={{ 
                    alignSelf: 'flex-start', 
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    transform: 'scale(0.7)',
                    transformOrigin: 'top left',
                    color: 'var(--ggui-color-onSurfaceVariant)'
                  }}
                >
                  {el.atomicNumber}
                </Text>
                <Text
                  variant="body"
                  weight="bold"
                  style={{ fontSize: 'var(--ggui-font-size-lg, 18px)', lineHeight: 1 }}
                >
                  {el.symbol}
                </Text>
                <Spacer size={0} />
              </button>
            );
          })}
        </Box>

        {/* Selected Element Details */}
        {selectedElement ? (
          <Card padding={24} shadow="md" radius="lg">
            <Stack direction="horizontal" gap={32} align="start" wrap>
              {/* Highlight Box */}
              <Box
