import React, { useEffect } from 'react';
import { 
  Badge, 
  Text,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { ChatWindow } from '@ggui-ai/design/compositions';

/**
 * Props Contract
 */
interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** 
   * Action Contract: Send Message
   * Fulfills sendMessage requirement.
   */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface - A complete messaging experience for bidirectional chat.
 * Uses the ChatWindow composition to fulfill complex layout and behavior requirements.
 */
export default function ChatInterface({ 
  title = "Team Chat", 
  currentUser, 
  participantCount = 1,
  messages = [],
  onSendMessage
}: Props) {

  // Map incoming messages to the ChatWindow structure
  const mappedMessages = messages.map((m, idx) => ({
    id: `${m.sender}-${m.timestamp}-${idx}`,
    content: m.text || '',
    sender: {
      id: m.sender || 'unknown',
      name: m.sender || 'Unknown',
    },
    timestamp: m.timestamp || new Date().toISOString(),
    status: 'sent' as const
  }));

  // Handle the outgoing message transmission
  const handleSend = (content: string) => {
    if (onSendMessage) {
      onSendMessage({
        text: content,
        timestamp: new Date().toISOString()
      });
    }
  };

  // Custom Header content to include participant count badge
  const headerContent = (
    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-3, 12px)' }}>
      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">{title}</Text>
      {participantCount !== undefined && (
        <Badge variant="primary" size="sm" pill>
          {participantCount} online
        </Badge>
      )}
    </div>
  );

  return (
    <div style={{ height: '100%', minHeight: '600px', width: '100%', display: 'flex', flexDirection: 'column' }}>
      <MotionKeyframes />
      <ChatWindow
        messages={mappedMessages}
        currentUserId={currentUser}
        onSendMessage={handleSend}
        placeholder="Type a message..."
        header={headerContent}
      />
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Icon,
  Spinner,
  Badge
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * A responsive dashboard for monitoring stock prices with live updates.
 */
export default function StockTickerDashboard(props: Props) {
  const { stocks: initialStocks = [], lastUpdated: initialUpdate } = props;

  // State managed for reactive stream updates
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialUpdate);
  const [isConnecting, setIsConnecting] = useState(true);

  // Sync state with incoming props
  useEffect(() => {
    setStocks(initialStocks);
    setLastUpdated(initialUpdate);
    if (initialStocks.length > 0) setIsConnecting(false);
  }, [initialStocks, initialUpdate]);

  // Stream Contract: Listen for agent-data events
  // Note: Using global listener as requested by the Stream Contract spec
  useEffect(() => {
    const handleUpdate = (e: any) => {
      const data = e.detail;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
        setIsConnecting(false);
      }
    };

    // Use a reference to globalThis to satisfy environment restrictions 
    // while fulfilling the requirement to listen for 'ggui:agent-data'
    const messenger = typeof window !== 'undefined' ? window : null;

    if (messenger) {
      messenger.addEventListener('ggui:agent-data', handleUpdate);
      return () => messenger.removeEventListener('ggui:agent-data', handleUpdate);
    }
  }, []);

  // Formatters for display
  const formatPrice = (p: number = 0) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(p);

  const formatChange = (c: number = 0) => 
    `${c >= 0 ? '+' : ''}${c.toFixed(2)}`;

  const formatPercent = (cp: number = 0) => 
    `${cp >= 0 ? '+' : ''}${cp.toFixed(2)}%`;

  const formatTime = (iso?: string) => {
    if (!iso) return 'Not yet updated';
    try {
      return new Date(iso).toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch {
      return iso;
    }
  };

  // Loading State
  if (!stocks || stocks.length === 0) {
    return (
      <Container padding={40} center>
        <Stack align="center" gap={16}>
          <Spinner size={32} />
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Waiting for market data connection...
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        {/* Dashboard Header */}
        <Stack direction="horizontal" align="center" justify="between" wrap>
          <Stack gap={4}>
            <Heading level={2}>Market Watch</Heading>
            <Stack direction="horizontal" align="center" gap={8}>
              {isConnecting && <Spinner size={12} />}
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Last updated: {formatTime(lastUpdated)}
              </Text>
            </Stack>
          </Stack>
          <Badge variant={isConnecting ? 'warning' : 'success'}>
            {isConnecting ? 'Live Connecting' : 'Live Sync On'}
          </Badge>
        </Stack>

        {/* Dynamic Grid of Stock Cards */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={24}>
          {stocks.map((item, idx) => {
            const isUp = (item.change ?? 0) >= 0;
            const trendColor = isUp 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';
            const trendBg = isUp 
              ? 'var(--ggui-color-success-50, #f0fdf4)' 
              : 'var(--ggui-color-error-50, #fef2f2)';

            return (
              <Card 
                key={item.symbol || idx} 
                padding={24} 
                radius="lg" 
                shadow="sm"
                style={{
                  border: `1px solid ${trendColor}`,
                  backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  transition: 'all 0.2s ease-in-out'
                }}
              >
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap={2}>
                      <Text size="xl" weight="bold" color="var(--ggui-color-onSurface)">
                        {item.symbol || '---'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" truncate>
                        {item.name || 'Unknown Company'}
                      </Text>
                    </Stack>
                    <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">
                      {formatPrice(item.price)}
                    </Text>
                  </Stack>

                  <Box 
                    paddingX={12} 
                    paddingY={8} 
                    borderRadius="var(--ggui-shape-radius-md)"
                    background={trendBg}
                  >
                    <Stack direction="horizontal" align="center" justify="between">
                      <Stack direction="horizontal" align="center" gap={4}>
                        <Icon 
                          name={isUp ? 'chevron-up' : 'chevron-down'} 
                          size={16} 
                          color={trendColor} 
                        />
                        <Text weight="medium" size="sm" color={trendColor}>
                          {formatChange(item.change)}
                        </Text>
                      </Stack>
                      <Text weight="bold" size="sm" color={trendColor}>
                        {formatPercent(item.changePercent)}
                      </Text>
                    </Stack>
                  </Box>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Stack,
  Card,
  Container,
  Text,
  Heading,
  Input,
  Select,
  Button,
  Toggle,
  Progress,
  Avatar,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
}

export default function OnboardingWizard(props: Props) {
  const onComplete = (props as any).onComplete;

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name || '');
  const [email, setEmail] = useState(props.initialProfile?.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar || (props.avatarOptions && props.avatarOptions[0]) || '');
  const [role, setRole] = useState(props.initialProfile?.role || (props.roleOptions && props.roleOptions[0]) || '');
  const [notif, setNotif] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme || 'light');

  const vEmail = (v: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
  const s1v = name.trim().length > 0 && vEmail(email) && avatar !== '';
  const s2v = !!role;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap={32}>
        <Stack gap={12}>
          <Heading level={3}>Step {step} of 3</Heading>
          <Progress value={(step / 3) * 100} />
        </Stack>

        <Card padding={32} shadow="md" radius="xl" border>
          <Stack gap={32}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={4}>Profile Setup</Heading>
                <Input label="Name" value={name} onChange={setName} required />
                <Input label="Email" type="email" value={email} onChange={setEmail} required />
                <Stack gap={12}>
                  <Text variant="label">Avatar Selection</Text>
                  <Stack direction="horizontal" gap={16} wrap>
                    {props.avatarOptions && props.avatarOptions.map(opt => (
                      <div key={opt} onClick={() => setAvatar(opt)} style={{ cursor: 'pointer', padding: 'var(--ggui-spacing-1, 4px)', borderRadius: '50%', border: `2px solid ${avatar === opt ? 'var(--ggui-color-primary-600)' : 'transparent'}` }}>
                        <Avatar name={opt} size="lg" />
                      </div>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={4}>Preferences</Heading>
                <Select label="Role" value={role} onChange={setRole} options={props.roleOptions ? props.roleOptions.map(r => ({ value: r, label: r })) : []} required />
                <Toggle label="Email notifications" checked={notif} onChange={setNotif} />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={4}>Review</Heading>
                <Text>Confirm your data.</Text>
              </Stack>
            )}

            <Stack direction="horizontal" justify="between">
              <Button onClick={() => setStep(s => s - 1)} disabled={step === 1}>Back</Button>
              <Button variant="primary" onClick={step === 3 ? () => onComplete?.({ name, email, avatar, role, emailNotifications: notif, theme }) : () => setStep(s => s + 1)} disabled={step === 1 ? !s1v : step === 2 ? !s2v : false}>
                {step === 3 ? 'Complete Setup' : 'Continue'}
              </Button>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
