interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * A visual representation of current weather and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 18,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 22, low: 14 },
    { day: 'Tue', icon: '☁️', high: 19, low: 13 },
    { day: 'Wed', icon: '🌧️', high: 16, low: 11 },
    { day: 'Thu', icon: '⛅', high: 20, low: 12 },
    { day: 'Fri', icon: '☀️', high: 23, low: 15 },
  ]
}: Props) {
  // Logic for wind unit based on temp unit
  const windUnit = unit === 'C' ? 'km/h' : 'mph';

  /**
   * Helper to map condition strings to emojis if no specific icon is provided.
   */
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    return '⛅';
  };

  return (
    <Card 
      padding={24} 
      radius="xl" 
      shadow="md"
    >
      <Stack gap={24}>
        {/* Header Section: City and Status */}
        <Stack gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current Conditions: {condition}
          </Text>
        </Stack>

        {/* Main Temperature and Big Emoji */}
        <Stack direction="horizontal" align="center" justify="between">
          <Stack gap={0}>
            <Heading 
              level={1} 
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}
            >
              {Math.round(temperature)}°{unit}
            </Heading>
          </Stack>
          <Text size="4xl">
            {getConditionEmoji(condition)}
          </Text>
        </Stack>

        <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* Current Details: Humidity and Wind */}
        <Stack direction="horizontal" justify="between">
          <Stack gap={4}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              HUMIDITY
            </Text>
            <Text variant="body" weight="semibold">
              {humidity}%
            </Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              WIND
            </Text>
            <Text variant="body" weight="semibold">
              {windSpeed} {windUnit}
            </Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Strip */}
        <Box 
          padding={16} 
          borderRadius="var(--ggui-shape-radius-lg, 12px)" 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        >
          <Stack direction="horizontal" justify="between" align="center" gap={12}>
            {forecast.slice(0, 5).map((item, index) => (
              <Stack key={item.day || index} align="center" gap={4}>
                <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day}
                </Text>
                <Text size="xl">
                  {item.icon || '☀️'}
                </Text>
                <Stack direction="horizontal" gap={4} justify="center">
                  <Text size="xs" weight="semibold">
                    {item.high}°
                  </Text>
                  <Text size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Stack,
  Card,
  Container,
  Progress,
  Text,
  Heading,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Callback for final submission */
  onSubmit?: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

/**
 * A multi-step survey form with progress tracking and validation.
 * Uses ggui primitives and theme tokens for consistent styling.
 */
export default function GeneratedComponent({
  featureOptions = ['Speed', 'Design', 'Reliability', 'Pricing'],
  satisfactionLabels = [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  const totalSteps = 5;

  const validateEmail = (email: string) => {
    return String(email)
      .toLowerCase()
      .match(
        /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
      );
  };

  const isStepValid = () => {
    if (step === 1) {
      return formData.name.trim() !== '' && !!validateEmail(formData.email);
    }
    if (step === 2) {
      return formData.satisfaction !== '';
    }
    return true;
  };

  const handleNext = () => {
    if (step === 1) {
      const nameErr = formData.name.trim() === '' ? 'Name is required' : '';
      const emailErr = !formData.email 
        ? 'Email is required' 
        : !validateEmail(formData.email) 
          ? 'Must be a valid email format' 
          : '';

      if (nameErr || emailErr) {
        setErrors({ name: nameErr, email: emailErr });
        return;
      }
    }
    if (step < totalSteps) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) await onSubmit(formData);
    } finally {
      setIsSubmitting(false);
    }
  };

  const satisfactionOptions = satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: label,
  }));

  return (
    <Container maxWidth="md" padding={24}>
      <Card padding={32} shadow="md" radius="xl" border={true}>
        <Stack gap={32}>
          {/* Progress Indication */}
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="end">
              <Stack gap={4}>
                <Text variant="overline" color="var(--ggui-color-primary-600)">
                  Survey Flow
                </Text>
                <Heading level={5}>
                  {step === totalSteps ? 'Final Review' : `Step ${step} of 4`}
                </Heading>
              </Stack>
              <Text variant="caption" weight="semibold">
                {Math.round((step / totalSteps) * 100)}%
              </Text>
            </Stack>
            <Progress value={step} max={totalSteps} variant="default" size="sm" />
          </Stack>

          {/* Survey Screens */}
          <Box style={{ minHeight: '340px' }}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={3}>Your Information</Heading>
                <Input label="Name" placeholder="Full Name" value={formData.name} error={errors.name} required={true} onChange={(v) => { setFormData(p => ({ ...p, name: v })); setErrors(p => ({ ...p, name: '' })); }} />
                <Input label="Email" type="email" placeholder="Email Address" value={formData.email} error={errors.email} required={true} onChange={(v) => { setFormData(p => ({ ...p, email: v })); setErrors(p => ({ ...p, email: '' })); }} />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={3}>Satisfaction</Heading>
                <RadioGroup
                  label="Rate your satisfaction"
                  value={formData.satisfaction}
                  options={satisfactionOptions}
                  onChange={(v) => setFormData(p => ({ ...p, satisfaction: v }))}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={3}>Interests</Heading>
                <Text variant="body">Select features you are interested in:</Text>
                <Stack gap={12}>
                  {featureOptions.map(opt => (
                    <Checkbox
                      key={opt}
                      label={opt}
                      checked={formData.features.includes(opt)}
                      onChange={(c) => setFormData(p => ({
                        ...p,
                        features: c ? [...p.features, opt] : p.features.filter(f => f !== opt)
                      }))}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={24}>
                <Heading level={3}>Final Comments</Heading>
                <TextArea
                  label="Anything else?"
                  placeholder="Additional thoughts..."
                  value={formData.comments}
                  onChange={(v) => setFormData(p => ({ ...p, comments: v }))}
                  maxLength={500}
                  showCount={true}
                  rows={6}
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap={24}>
                <Heading level={3}>Review</Heading>
                <Box padding={20} borderRadius="lg" background="var(--ggui-color-surfaceVariant)" style={{ border: '1px solid var(--ggui-color-outline)' }}>
                  <Stack gap={20}>
                    <Stack gap={4}><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text><Text>{formData.name}</Text></Stack>
                    <Stack gap={4}><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text><Text>{formData.email}</Text></Stack>
                    <Stack gap={4}><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text><Text>{satisfactionLabels[parseInt(formData.satisfaction)-1] || 'N/A'}</Text></Stack>
                    <Stack gap={4}><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features</Text><Text>{formData.features.join(', ') || 'None'}</Text></Stack>
                    <Stack gap={4}><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text><Text>{formData.comments || 'No comment'}</Text></Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin={8} />

          {/* Navigation Controls */}
          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1 || isSubmitting}>Back</Button>
            {step < totalSteps ? (
              <Button variant="primary" onClick={handleNext} disabled={!isStepValid()}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Badge
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const CATEGORY_MAP: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'transition metal': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'post-transition metal': 'var(--ggui-color-success-100, #dcfce7)',
  'metalloid': 'var(--ggui-color-info-100, #cffafe)',
  'polyatomic nonmetal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'diatomic nonmetal': 'var(--ggui-color-primary-50, #f0f9ff)',
  'noble gas': 'var(--ggui-color-primary-200, #bae6fd)',
  'lanthanide': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'actinide': 'var(--ggui-color-neutral-300, #d1d5db)',
  'unknown': 'var(--ggui-color-neutral-50, #f9fafb)',
};

/**
 * Interactive Periodic Table of Elements.
 * Displays elements in a standard grid layout with search and detail views.
 */
export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase().trim();
    if (!term) return elements;
    return elements.filter(e => 
      e.name?.toLowerCase().includes(term) || 
      e.symbol?.toLowerCase().includes(term)
    );
  }, [elements, searchTerm]);

  const categories = useMemo(() => {
    const set = new Set(elements.map(e => e.category).filter(Boolean));
    return Array.from(set).sort() as string[];
  }, [elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={32}>
        {/* Header Section */}
        <Stack gap={16} align="center">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Box style={{ width: '100%', maxWidth: '600px' }}>
            <SearchField 
              value={searchTerm} 
              onChange={setSearchTerm}
              placeholder="Search by name or symbol..."
              size="lg"
            />
          </Box>
        </Stack>

        {/* Periodic Grid */}
        <Box 
          style={{ 
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-6, 24px)'
          }}
        >
          <div 
            style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(18, minmax(52px, 1fr))', 
              gap: 'var(--ggui-spacing-1, 4px)', 
              minWidth: '1050px',
              padding: 'var(--ggui-spacing-1, 4px)'
            }}
          >
            {elements.map((el) => {
              const isMatch = filteredElements.some(f => f.atomicNumber === el.atomicNumber);
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const categoryColor = CATEGORY_MAP[el.category || 'unknown'] || CATEGORY_MAP.unknown;

              return (
                <div
                  key={el.atomicNumber}
                  onClick={() => setSelectedElement(el)}
                  role="button"
                  tabIndex={0}
                  aria-pressed={isSelected}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault();
                      setSelectedElement(el);
                    }
                  }}
                  style={{ 
                    gridRow: el.row, 
                    gridColumn: el.col,
                    backgroundColor: categoryColor,
                    border: isSelected 
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                      : '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'space-between',
                    aspectRatio: '1/1',
                    opacity: isMatch ? 1 : 0.2,
                    transition: 'transform 0.15s ease, box-shadow 0.15s, opacity 0.3s',
                    transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1,
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
                    outline: 'none',
                  }}
                >
                  <Text variant="caption" size="xs" weight="bold">
                    {el.atomicNumber}
                  </Text>
                  <Text align="center" weight="bold" size="lg" style={{ lineHeight: 1 }}>
                    {el.symbol}
                  </Text>
                  <Text variant="caption" align="center" truncate style={{ fontSize: '10px' }}>
                    {el.name}
                  </Text>
                </div>
              );
            })}
          </div>
        </Box>

        {/* Legend */}
        <Stack direction="horizontal" wrap gap={12} justify="center">
          {categories.map(cat => (
            <Stack key={cat} direction="horizontal" gap={8} align="center">
              <div style={{ 
                width: '16px', 
                height: '16px', 
                backgroundColor: CATEGORY_MAP[cat] || CATEGORY_MAP.unknown, 
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                border: '1px solid var(--ggui-color-neutral-300, #d1d5db)'
              }} />
              <Text variant="caption" weight="medium" style={{ textTransform: 'capitalize' }}>{cat}</Text>
            </Stack>
          ))}
        </Stack>

        {/* Detailed Inspection Panel */}
        {selectedElement ? (
          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="lg">
              <Stack direction="horizontal" gap={32} align="center" wrap>
                {/* Element Block Preview */}
                <div style={{
                  width: '120px',
                  height: '120px',
                  backgroundColor: CATEGORY_MAP[selectedElement.category || 'unknown'] || CATEGORY_MAP.unknown,
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                  boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'
                }}>
                  <Heading level={1}>{selectedElement.symbol}</Heading>
                  <Text weight="bold" size="lg">{selectedElement.atomicNumber}</Text>
                </div>

                {/* Details List */}
                <Stack gap={24} style={{ flex: 1 }}>
                  <Stack direction="horizontal" justify="between" align="center" wrap gap={16}>
                    <Stack gap={4}>
                      <Heading level={2}>{selectedElement.name}</Heading>
                      <Text color="var(--ggui-color-neutral-500, #6b7280)" weight="medium">
                        {selectedElement.category}
                      </Text>
                    </Stack>
                    <Badge variant="primary" size="lg" pill={false}>
                      Element {selectedElement.atomicNumber}
                    </Badge>
                  </Stack>

                  <Box style={{ 
                    display: 'grid', 
                    gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', 
                    gap: 'var(--ggui-spacing-6, 24px)' 
                  }}>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Atomic Weight</Text>
                      <Text size="lg" weight="semibold">{selectedElement.atomicWeight} u</Text>
                    </Stack>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Position</Text>
                      <Text size="lg" weight="semibold">Period {selectedElement.row}, Group {selectedElement.col}</Text>
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            </Card>
          </Box>
        ) : (
          <Box 
            padding="var(--ggui-spacing-8, 32px)"
            style={{ 
              border: '2px dashed var(--ggui-color-neutral-200, #e5e7eb)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              display: 'flex',
              justifyContent: 'center'
            }}
          >
            <Text color="var(--ggui-color-neutral-500, #6b7280)" align="center">
              Select an element to view detailed properties
            </Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Button, Input, Badge, Box } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<Message>;
  /** Action called when sending a message. Payload: { text, timestamp } */
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface Component
 * 
 * Provides a real-time chat interface.
 * Implements auto-scroll, message grouping, and primary/surfaceVariant bubbles.
 */
export default function ChatInterface(props: Props) {
  const { 
    title = "Chat", 
    currentUser = "User", 
    participantCount, 
    messages = [], 
    sendMessage 
  } = props;

  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom of message list on update
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    const text = inputValue.trim();
    if (!text) return;

    // Action Contract implementation
    sendMessage?.({
      text,
      timestamp: new Date().toISOString()
    });

    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Card 
      padding={0} 
      shadow="md" 
      radius="lg" 
      border={true}
      style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        height: '600px', 
        width: '100%',
        maxWidth: '500px',
        margin: '0 auto',
        overflow: 'hidden',
        background: 'var(--ggui-color-surface, #ffffff)'
      }}
    >
      {/* Header section with Title and optional online count */}
      <Box padding={16} style={{ borderBottom: '1px solid var(--ggui-color-outline, #e5e7eb)', background: 'var(--ggui-color-surface, #ffffff)' }}>
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" gap={8} align="center">
            <Text variant="label" size="lg" weight="bold" color="var(--ggui-color-onSurface, #111827)">
              {title}
            </Text>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm">
                {participantCount} active
              </Badge>
            )}
          </Stack>
        </Stack>
      </Box>

      {/* Message List area with auto-scrolling container */}
      <div 
        ref={scrollRef}
        style={{ 
          flex: 1, 
          overflowY: 'auto', 
          background: 'var(--ggui-color-surface, #ffffff)',
          scrollBehavior: 'smooth',
          padding: 'var(--ggui-spacing-4, 16px)'
        }}
      >
        <Stack gap={16}>
          {messages.map((msg, idx) => {
            const isMe = msg.sender === currentUser;
            const prev = messages[idx - 1];
            // Consecutive messages grouping: hide name if sender is same as previous
            const isFirst = !prev || prev.sender !== msg.sender;

            return (
              <Stack 
                key={`${idx}-${msg.timestamp}`} 
                align={isMe ? 'end' : 'start'} 
                gap={4}
              >
                {isFirst && !isMe && msg.sender && (
                  <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                    {msg.sender}
                  </Text>
                )}
                <Box
                  paddingX={12}
                  paddingY={8}
                  borderRadius={12}
                  background={isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f3f4f6)'}
                  style={{
                    maxWidth: '85%',
                    borderBottomRightRadius: isMe ? '4px' : '12px',
                    borderBottomLeftRadius: isMe ? '12px' : '4px',
                  }}
                >
                  <Stack gap={4}>
                    <Text variant="bodySmall" color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #111827)'}>
                      {msg.text || ''}
                    </Text>
                    <Text 
                      variant="caption" 
                      align={isMe ? 'right' : 'left'}
                      color={isMe ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #6b7280)'}
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Stack>
                </Box>
              </Stack>
            );
          })}
        </Stack>
      </div>

      {/* Message Input area */}
      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outline, #e5e7eb)', background: 'var(--ggui-color-surface, #ffffff)' }}>
        <Stack direction="horizontal" gap={12} align="end">
          <Input label="New Message" id="chat-msg-input" placeholder="Type a message..." value={inputValue} onChange={setInputValue} onKeyDown={handleKeyDown} />
          <Button 
            variant="primary" 
            disabled={!inputValue.trim()}
            onClick={handleSend}
            aria-label="Send Message"
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Text,
  Heading,
  Box,
  Spinner,
  Icon
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * A responsive dashboard for monitoring stock price updates in real-time.
 */
export default function StockTickerDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  // Use props as initial state
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isLive, setIsLive] = useState(false);

  // Sync state if initial props change
  useEffect(() => {
    if (initialStocks && initialStocks.length > 0) {
      setStocks(initialStocks);
    }
  }, [initialStocks]);

  useEffect(() => {
    if (initialLastUpdated) {
      setLastUpdated(initialLastUpdated);
    }
  }, [initialLastUpdated]);

  // Handle live data stream from the agent using a global listener
  useEffect(() => {
    const handleStream = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;

      if (data) {
        if (data.stocks && Array.isArray(data.stocks)) {
          setStocks(data.stocks);
          setIsLive(true);
        }
        if (data.lastUpdated) {
          setLastUpdated(data.lastUpdated);
        }
      }
    };

    // Use global listener for the stream contract
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleStream);
      return () => removeEventListener('ggui:agent-data', handleStream);
    }
  }, []);

  const formatTime = (isoString?: string) => {
    if (!isoString) return '--:--';
    try {
      return new Date(isoString).toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch {
      return 'Invalid';
    }
  };

  // Loading state if we have no stocks yet
  if (!stocks || stocks.length === 0) {
    return (
      <Container maxWidth="xl" padding={24}>
        <Stack align="center" justify="center" gap={16} style={{ minHeight: '300px' }}>
          <Spinner size={32} />
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
            Connecting to market watch...
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* Dashboard Header */}
        <Stack direction="horizontal" align="center" justify="between" wrap gap={16}>
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface)">Market Watch</Heading>
            <Stack direction="horizontal" align="center" gap={8}>
              <Box 
                borderRadius="full" 
                style={{ 
                  width: 8, 
                  height: 8, 
                  backgroundColor: isLive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-outline)',
                  boxShadow: isLive ? '0 0 0 4px var(--ggui-color-success-100)' : 'none'
                }} 
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {isLive ? 'Live Feed Active' : 'Market Standby'}
              </Text>
            </Stack>
          </Stack>

          <Box 
            paddingX={16} 
            paddingY={8} 
            borderRadius={24} 
            background="var(--ggui-color-surfaceVariant)"
            style={{ border: '1px solid var(--ggui-color-outline)' }}
          >
            <Text variant="label" size="xs" weight="semibold" color="var(--ggui-color-onSurface)">
              LAST UPDATED: {formatTime(lastUpdated)}
            </Text>
          </Box>
        </Stack>

        {/* Stock Grid */}
        <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={16}>
          {stocks.map((stock, index) => {
            const price = stock.price ?? 0;
            const change = stock.change ?? 0;
            const isPositive = change >= 0;

            // Color tokens based on market performance
            const statusColor = isPositive 
              ? 'var(--ggui-color-success-600)' 
              : 'var(--ggui-color-error-600)';
            const statusBg = isPositive 
              ? 'var(--ggui-color-success-50)' 
              : 'var(--ggui-color-error-50)';
            const statusBorder = isPositive 
              ? 'var(--ggui-color-success-200)' 
              : 'var(--ggui-color-error-200)';

            return (
              <Card 
                key={`${stock.symbol || 'stock'}-${index}`} 
                padding={20} 
                shadow="sm"
                style={{ 
                  borderColor: statusBorder,
                  transition: 'border-color 200ms ease-in-out',
                  borderWidth: '1.5px',
                  background: 'var(--ggui-color-surface)'
                }}
              >
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap={2}>
                      <Text 
                        size="2xl" 
                        weight="bold" 
                        color="var(--ggui-color-onSurface)"
                        style={{ letterSpacing: 'var(--ggui-font-letterSpacing-tight, -0.025em)' }}
                      >
                        {stock.symbol || '---'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" truncate>
                        {stock.name || 'Unknown Company'}
                      </Text>
                    </Stack>
                    <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                      ${price.toFixed(2)}
                    </Text>
                  </Stack>

                  <Box 
                    padding={10} 
                    borderRadius="md" 
                    background={statusBg}
                    style={{ border: `1px solid ${statusBorder}` }}
                  >
                    <Stack direction="horizontal" justify="between" align="center">
                      <Stack direction="horizontal" gap={4} align="center">
                        <Icon 
                          name={isPositive ? 'chevron-up' : 'chevron-down'} 
                          size={16} 
                          color={statusColor} 
                        />
                        <Text weight="bold" color={statusColor} size="sm">
                          {isPositive ? '+' : ''}{change.toFixed(2)}
                        </Text>
                      </Stack>
                      <Text weight="bold" color={statusColor} size="sm">
                        {isPositive ? '+' : ''}{stock.changePercent?.toFixed(2) || '0.00'}%
                      </Text>
                    </Stack>
                  </Box>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

