    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions.length > 0 ? avatarOptions[0] : ''),
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = useMemo(() => {
    return formData.name.trim().length > 0 && 
           formData.email.trim().length > 0 && 
           isValidEmail(formData.email) && 
           formData.avatar !== '';
  }, [formData.name, formData.email, formData.avatar]);

  const isStep2Valid = useMemo(() => formData.role !== '', [formData.role]);

  const handleNext = () => setCurrentStep((prev) => Math.min(prev + 1, 3));
  const handleBack = () => setCurrentStep((prev) => Math.max(prev - 1, 1));
  const handleComplete = () => onComplete?.(formData);

  const updateField = (key: string, value: any) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding={32} radius="xl" border>
        <Stack gap={24}>
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="end">
              <Heading level={3} color="var(--ggui-color-primary-600)">Welcome</Heading>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Step {currentStep} of 3</Text>
            </Stack>
            <Progress value={(currentStep / 3) * 100} size="sm" variant="default" />
          </Stack>

          <Box style={{ minHeight: '340px' }}>
            {currentStep === 1 && (
              <Stack gap={24} style={{ animation: 'ggui-fadeIn 300ms ease-out' }}>
                <Stack gap={4}>
                  <Heading level={4}>1. Profile Setup</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Enter your details.</Text>
                </Stack>
                <Stack gap={16}>
                  <Input label="Name" placeholder="Full Name" value={formData.name} onChange={(v) => updateField('name', v)} required />
                  <Input label="Email" placeholder="Email Address" value={formData.email} onChange={(v) => updateField('email', v)} required error={formData.email && !isValidEmail(formData.email) ? 'Invalid email' : undefined} />
                  <Stack gap={8}>
                    <Text variant="label" weight="medium">Select Avatar</Text>
                    <Stack direction="horizontal" gap={12} wrap>
                      {avatarOptions.map((emoji) => (
                        <button
                          key={emoji}
                          type="button"
                          onClick={() => updateField('avatar', emoji)}
                          style={{
                            padding: 'var(--ggui-spacing-1)',
                            borderRadius: 'var(--ggui-shape-radius-lg)',
                            backgroundColor: formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'transparent',
                            border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`,
                            cursor: 'pointer',
                            display: 'flex',
                          }}
                        >
                          <Avatar name={emoji} size="lg" />
                        </button>
                      ))}
                    </Stack>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={24} style={{ animation: 'ggui-fadeIn 300ms ease-out' }}>
                <Stack gap={4}>
                  <Heading level={4}>2. Preferences</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Set your app settings.</Text>
                </Stack>
                <Stack gap={20}>
                  <Select label="Role" placeholder="Choose role" value={formData.role} onChange={(v) => updateField('role', v)} options={roleOptions.map(r => ({ label: r, value: r }))} required />
                  <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
                  <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
                </Stack>
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={24} style={{ animation: 'ggui-fadeIn 300ms ease-out' }}>
                <Stack gap={4}>
                  <Heading level={4}>3. Review</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Confirm your details.</Text>
                </Stack>
                <Box padding={24} borderRadius="var(--ggui-shape-radius-xl)" background="var(--ggui-color-surfaceVariant)" style={{ border: '1px solid var(--ggui-color-outline)' }}>
                  <Stack gap={20}>
                    <Stack direction="horizontal" gap={16} align="center">
                      <Avatar name={formData.avatar} size="xl" />
                      <Stack gap={2}>
                        <Text variant="bodyLarge" weight="bold">{formData.name}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin={0} />
                    <Stack gap={12}>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                        <Text variant="bodySmall" weight="medium">{formData.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Notifications</Text>
                        <Text variant="bodySmall" weight="medium">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                        <Text variant="bodySmall" weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin={8} />
          <Stack direction="horizontal" justify="between">
            <Button variant="outline" onClick={handleBack} disabled={currentStep === 1}>Back</Button>
            {currentStep < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={currentStep === 1 ? !isStep1Valid : !isStep2Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleComplete}>Complete</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
