import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Progress,
  Divider,
  Checkbox,
  RadioGroup,
  Box
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called with all collected answers as a structured object */
  onSubmit?: (data: any) => void;
}

/**
 * Multi-step Survey Component
 */
export default function SurveyForm(props: Props) {
  const { 
    featureOptions = ['A', 'B', 'C'], 
    satisfactionLabels = ['1', '2', '3'], 
    onSubmit 
  } = props;

  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: ''
  });

  const [loading, setLoading] = useState(false);
  const [done, setDone] = useState(false);

  const isEmailValid = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);

  const canContinue = useMemo(() => {
    if (step === 1) return data.name.trim().length > 0 && isEmailValid(data.email);
    if (step === 2) return data.satisfaction !== '';
    return true;
  }, [step, data]);

  const toggleFeature = (f: string, c: boolean) => {
    setData(prev => ({
      ...prev,
      features: c ? [...prev.features, f] : prev.features.filter(x => x !== f)
    }));
  };

  if (done) {
    return (
      <Container padding={40}>
        <Card shadow="md" padding={40} radius="xl">
          <Heading level={2}>Success</Heading>
          <Text>Your survey has been submitted!</Text>
        </Card>
      </Container>
    );
  }

  const renderContent = () => {
    if (step === 1) return (
      <Stack gap={20}>
        <Input label="Name" value={data.name} onChange={v => setData(p => ({...p, name: v}))} required />
        <Input label="Email" type="email" value={data.email} onChange={v => setData(p => ({...p, email: v}))} required />
      </Stack>
    );
    if (step === 2) return (
      <RadioGroup
        label="Satisfaction"
        value={data.satisfaction}
        onChange={v => setData(p => ({...p, satisfaction: v}))}
        options={satisfactionLabels.map((l, i) => ({ label: l, value: String(i+1) }))}
      />
    );
    if (step === 3) return (
      <Stack gap={12}>
        <Text variant="label">Feature Interests</Text>
        {featureOptions.map(f => (
          <Checkbox key={f} label={f} checked={data.features.includes(f)} onChange={c => toggleFeature(f, c)} />
        ))}
      </Stack>
    );
    if (step === 4) return (
      <TextArea label="Comments" value={data.comments} onChange={v => setData(p => ({...p, comments: v}))} maxLength={500} showCount />
    );
    return (
      <Stack gap={16}>
        <Heading level={4}>Review</Heading>
        <Text>Name: {data.name}</Text>
        <Text>Email: {data.email}</Text>
        <Text>Satisfaction: {data.satisfaction}</Text>
        <Text>Features: {data.features.join(', ') || 'None'}</Text>
        <Text>Comments: {data.comments || 'None'}</Text>
      </Stack>
    );
  };

  return (
    <Container maxWidth="md" padding={32}>
      <Card shadow="md" padding={32} radius="xl">
        <Stack gap={32}>
          <Stack gap={8}>
            <Heading level={2}>Step {step > 4 ? 4 : step} of 4</Heading>
            <Progress value={step > 4 ? 4 : step} max={4} />
          </Stack>

          <Box style={{ minHeight: '300px' }}>
            {renderContent()}
          </Box>

          <Divider />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" disabled={step === 1} onClick={() => setStep(step - 1)}>Back</Button>
            {step < 5 ? (
              <Button disabled={!canContinue} onClick={() => setStep(step + 1)}>Next</Button>
            ) : (
              <Button loading={loading} onClick={() => {
                setLoading(true);
                setTimeout(() => { onSubmit?.(data); setLoading(false); setDone(true); }, 1000);
              }}>Submit</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

