const CATEGORY_PALETTE = [
  'var(--ggui-color-primary-100, #e0f2fe)',
  'var(--ggui-color-success-100, #dcfce7)',
  'var(--ggui-color-warning-100, #fef3c7)',
  'var(--ggui-color-error-100, #fee2e2)',
  'var(--ggui-color-info-100, #cffafe)',
  'var(--ggui-color-primary-200, #bae6fd)',
  'var(--ggui-color-success-200, #bbf7d0)',
  'var(--ggui-color-warning-200, #fde68a)',
  'var(--ggui-color-error-200, #fecaca)',
  'var(--ggui-color-info-200, #a5f3fc)',
  'var(--ggui-color-neutral-200, #e5e7eb)',
];

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColors = useMemo(() => {
    const map = new Map<string, string>();
    let colorIndex = 0;
    elements.forEach((el) => {
      const cat = el.category || 'Unknown';
      if (!map.has(cat)) {
        map.set(cat, CATEGORY_PALETTE[colorIndex % CATEGORY_PALETTE.length]);
        colorIndex++;
      }
    });
    return map;
  }, [elements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return elements.find((el) => el.atomicNumber === selectedAtomicNumber) || null;
  }, [elements, selectedAtomicNumber]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    return elements.map((el) => ({
      ...el,
      isVisible: !query || 
        (el.name || '').toLowerCase().includes(query) ||
        (el.symbol || '').toLowerCase().includes(query) ||
        (el.atomicNumber || '').toString().includes(query),
    }));
  }, [elements, searchQuery]);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={32}>
        <Stack gap={16}>
          <Stack gap={4}>
            <Text variant="bodyLarge" weight="bold" size="3xl" color="var(--ggui-color-onSurface, #18181b)">
              Periodic Table
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Explore properties of the chemical elements.
            </Text>
          </Stack>

          <SearchField
            value={searchQuery}
            onChange={setSearchQuery}
            placeholder="Search by name, symbol, or atomic number..."
          />
        </Stack>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            boxShadow: 'var(--ggui-shape-shadow-sm)',
          }}
        >
          {filteredElements.map((el) => {
            const isMatch = el.isVisible;
            const bgColor = categoryColors.get(el.category || 'Unknown') || 'var(--ggui-color-neutral-100)';
            const isSelected = selectedAtomicNumber === el.atomicNumber;

            return (
              <Button
                key={el.atomicNumber}
                variant="ghost"
                onClick={() => isMatch && setSelectedAtomicNumber(el.atomicNumber || null)}
                disabled={!isMatch}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1 / 1',
                  opacity: isMatch ? 1 : 0.1,
                  backgroundColor: bgColor,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                  border: isSelected
                    ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                    : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                  transform: isSelected ? 'scale(1.15)' : 'none',
                  zIndex: isSelected ? 10 : 1,
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'space-between',
                  alignItems: 'stretch',
                  height: 'auto',
                  minWidth: '0',
                  minHeight: '0'
