import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Box,
  Heading,
  Text,
  Badge,
  Input,
  Button,
  Avatar,
  Icon,
} from '@ggui-ai/design/primitives';

/**
 * Message
 */
interface ChatMsg {
  sender?: string;
  text?: string;
  timestamp?: string;
}

/**
 * Props Contract
 */
interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: ChatMsg[];
  /** Action Contract: sendMessage (Send Message) */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface Component
 */
export default function ChatInterface(props: Props) {
  const {
    title = 'Chat',
    currentUser = 'User',
    participantCount = 0,
    messages = [],
    onSendMessage,
  } = props;

  const [localMsgs, setLocalMsgs] = useState<ChatMsg[]>(messages);
  const [draft, setDraft] = useState('');
  const endRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setLocalMsgs(messages);
  }, [messages]);

  useEffect(() => {
    if (endRef.current) {
      endRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [localMsgs]);

  const onSendAction = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!draft.trim()) return;

    const ts = new Date().toISOString();
    setLocalMsgs(prev => [...prev, { text: draft, timestamp: ts, sender: currentUser }]);

    if (onSendMessage) {
      onSendMessage({ text: draft, timestamp: ts });
    }

    setDraft('');
  };

  return (
    <Card shadow="md" radius="lg" padding={0} border>
      <Box style={{ height: '600px', display: 'flex', flexDirection: 'column', backgroundColor: 'var(--ggui-color-surface, #ffffff)' }}>
        <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <Stack direction="horizontal" align="center" gap={12}>
            <Heading level={4}>{title}</Heading>
            <Badge variant="secondary" pill>{participantCount} participants</Badge>
          </Stack>
        </Box>

        <Box padding="var(--ggui-spacing-4, 16px)" style={{ flex: 1, overflowY: 'auto' }}>
          <Stack gap={16}>
            {localMsgs.map((m, i) => (
              <Stack key={i} direction="horizontal" justify={m.sender === currentUser ? 'end' : 'start'} gap={8} style={{ marginTop: (i > 0 && localMsgs[i-1].sender === m.sender) ? 'var(--ggui-spacing-1, -8px)' : '0' }}>
                {m.sender !== currentUser && (i === 0 || localMsgs[i-1].sender !== m.sender) && <Avatar name={m.sender} size="sm" />}
                {m.sender !== currentUser && (i > 0 && localMsgs[i-1].sender === m.sender) && <Box style={{ width: 'var(--ggui-spacing-8, 32px)' }} />}
                <Stack align={m.sender === currentUser ? 'end' : 'start'} gap={4} style={{ maxWidth: '80%' }}>
                  {(i === 0 || localMsgs[i-1].sender !== m.sender) && (
                    <Text variant="label" size="sm" color="var(--ggui-color-onSurfaceVariant)">{m.sender === currentUser ? 'You' : m.sender}</Text>
                  )}
                  <Box paddingX="var(--ggui-spacing-4, 16px)" paddingY="var(--ggui-spacing-2, 8px)" style={{ 
                    backgroundColor: m.sender === currentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    color: m.sender === currentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)',
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                  }}>
                    <Text variant="bodySmall" color="inherit">{m.text}</Text>
                  </Box>
                </Stack>
              </Stack>
            ))}
            <div ref={endRef} />
          </Stack>
        </Box>

        <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <form onSubmit={onSendAction} aria-label="Chat Form">
            <Stack direction="horizontal" align="end" gap={12}>
              <Box style={{ flex: 1 }}>
                <Text variant="label" size="sm">Your message</Text>
                <Input label="Your message" placeholder="Type..." value={draft} onChange={setDraft} />
              </Box>
              <Button variant="primary" type="submit" disabled={!draft.trim()}>Send</Button>
            </Stack>
          </form>
        </Box>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Card,
  Icon,
  Badge,
  Spinner,
  Box,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  lastUpdated?: string;
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const { stocks, lastUpdated } = props;
  const [liveStocks, setLiveStocks] = useState(stocks || []);
  const [liveLastUpdated, setLiveLastUpdated] = useState(lastUpdated);

  useEffect(() => {
    if (stocks) setLiveStocks(stocks);
    if (lastUpdated) setLiveLastUpdated(lastUpdated);
  }, [stocks, lastUpdated]);

  useEffect(() => {
    const handleData = (event: any) => {
      const data = event.detail;
      if (data?.stocks) setLiveStocks(data.stocks);
      if (data?.lastUpdated) setLiveLastUpdated(data.lastUpdated);
    };

    // Listen for agent data events
    addEventListener('ggui:agent-data', handleData);
    return () => removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Stack direction="horizontal" align="center" gap={12}>
            <Heading level={2}>Market Watch</Heading>
            <Badge variant="success">Live</Badge>
          </Stack>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            <span aria-live="polite">
              {liveLastUpdated ? `Last Updated: ${new Date(liveLastUpdated).toLocaleTimeString()}` : 'Connecting...'}
            </span>
          </Text>
        </Stack>

        {(!liveStocks || liveStocks.length === 0) ? (
          <Box paddingY="var(--ggui-spacing-12, 48px)">
            <Stack align="center" justify="center" gap={16}>
              <Spinner size={32} />
              <Text>Waiting for market data...</Text>
            </Stack>
          </Box>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {liveStocks.map((s) => {
              const pos = (s.change || 0) >= 0;
              const clr = pos ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
              const bc = pos ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-error-500, #ef4444)';
              return (
                <div key={s.symbol || Math.random()} style={{ '--ggui-color-neutral-200': bc } as React.CSSProperties}>
                  <Card padding={20} shadow="sm" radius="lg">
                    <Stack gap={16}>
                      <Stack direction="horizontal" justify="between" align="start">
                        <Stack gap={0}>
                          <Text size="lg" weight="bold">{s.symbol || '---'}</Text>
                          <Text variant="caption">{s.name || '---'}</Text>
                        </Stack>
                        <Icon name={pos ? 'chevron-up' : 'chevron-down'} size={20} color={clr} />
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="end">
                        <Text size="2xl" weight="semibold">{s.price ? `$${s.price.toFixed(2)}` : '$0.00'}</Text>
                        <Stack direction="horizontal" gap={4}>
                          <Text variant="bodySmall" color={clr}>{s.change ? (s.change >= 0 ? '+' : '') + s.change.toFixed(2) : '0.00'}</Text>
                          <Text variant="bodySmall" color={clr}>{s.changePercent ? `(${(s.changePercent >= 0 ? '+' : '')}${s.changePercent.toFixed(2)}%)` : '(0.00%)'}</Text>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Card>
                </div>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Divider,
  Icon,
  Avatar
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string; 
  };
  onComplete: (data: { 
    name: string; 
    email: string; 
    avatar: string; 
    role: string; 
    emailNotifications: boolean; 
    theme: string; 
  }) => void;
}

export default function OnboardingWizard(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, onComplete } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions[0] ? avatarOptions[0] : ''),
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const isStep1Valid = formData.name.trim().length > 0 && formData.email.includes('@');
  const isStep2Valid = formData.role !== '';

  const handleNext = () => setStep(step + 1);
  const handleBack = () => setStep(step - 1);
  const handleComplete = () => onComplete(formData);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        <Progress value={(step / 3) * 100} />
        <Card border padding="var(--ggui-spacing-6, 24px)">
          <div key={step}>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <div>
                   <Text as="label" variant="label">Name</Text>
                   <Input label="Name" value={formData.name} onChange={(v) => setFormData({...formData, name: v})} required />
                </div>
                <div>
                   <Text as="label" variant="label">Email</Text>
                   <Input label="Email" type="email" value={formData.email} onChange={(v) => setFormData({...formData, email: v})} required />
                </div>
                <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                  {avatarOptions.map(emoji => (
                    <Button key={emoji} variant={formData.avatar === emoji ? 'primary' : 'outline'} onClick={() => setFormData({...formData, avatar: emoji})}>{emoji}</Button>
                  ))}
                </Stack>
              </Stack>
            )}
            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Select label="Role" value={formData.role} onChange={(v) => setFormData({...formData, role: v})} options={roleOptions.map(r => ({ value: r, label: r }))} required />
                <Toggle label="Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({...formData, emailNotifications: v})} />
                <Toggle label="Dark Mode" checked={formData.theme === 'dark'} onChange={(v) => setFormData({...formData, theme: v ? 'dark' : 'light'})} />
              </Stack>
            )}
            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Avatar name={formData.avatar} size={64} />
                <Text>Review Your Details</Text>
                <Divider />
                <Text>Name: {formData.name}</Text>
                <Text>Email: {formData.email}</Text>
                <Text>Role: {formData.role}</Text>
              </Stack>
            )}
          </div>
        </Card>
        <Stack direction="horizontal" justify="between">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Go Back</Button>
          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={!isStep1Valid || (step === 2 && !isStep2Valid)}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleComplete}>Complete</Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Heading, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<ForecastItem>;
}

/**
 * WeatherCard component displays current weather information and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'New York',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 60 },
    { day: 'Tue', icon: '⛅', high: 73, low: 58 },
    { day: 'Wed', icon: '☁️', high: 70, low: 55 },
    { day: 'Thu', icon: '🌧️', high: 65, low: 52 },
    { day: 'Fri', icon: '☀️', high: 72, low: 58 },
  ],
}: Props) {
  // Helper to get a main emoji based on the condition string
  const getConditionEmoji = (cond: string) => {
    const lower = cond.toLowerCase();
    if (lower.includes('sun') || lower.includes('clear')) return '☀️';
    if (lower.includes('cloud')) return '☁️';
    if (lower.includes('rain')) return '🌧️';
    if (lower.includes('snow')) return '❄️';
    if (lower.includes('storm')) return '⛈️';
    return '⛅'; // default
  };

  return (
    <Card padding={24} radius="lg" shadow="md" border={true}>
      <Stack gap={24}>

        {/* Top Section: City, Condition, and Large Temperature */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition}
            </Text>
          </Stack>

          <Stack direction="horizontal" align="center" gap={12}>
            <Text size="4xl" color="var(--ggui-color-onSurface, #18181b)">
              {getConditionEmoji(condition)}
            </Text>
            <Stack direction="horizontal" align="start" gap={2}>
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                {temperature}
              </Text>
              <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                °{unit}
              </Text>
            </Stack>
          </Stack>
        </Stack>

        {/* Middle Section: Humidity and Wind Stats */}
        <Stack direction="horizontal" gap={16}>
          <Box 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius={8} 
            padding={16} 
            style={{ flex: 1 }}
          >
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Box>
          <Box 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius={8} 
            padding={16} 
            style={{ flex: 1 }}
          >
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind Speed
              </Text>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} mph
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* Bottom Section: 5-Day Forecast */}
        <Stack direction="horizontal" justify="between">
          {forecast.map((item, index) => (
            <Stack key={item.day || index} gap={8} align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day}
              </Text>
              <Text size="2xl">
                {item.icon}
              </Text>
              <Stack direction="horizontal" gap={4}>
                <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>

      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Stack,
  Card,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Progress,
  Checkbox,
  RadioGroup,
  Container,
  Divider,
  Box,
  Badge
} from '@ggui-ai/design/primitives';
import { FormField } from '@ggui-ai/design/components';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

export default function GeneratedComponent({
  featureOptions = ['Speed', 'UI Design', 'Ease of Use', 'Customer Support'],
  satisfactionLabels = ['Unsatisfied', 'Neutral', 'Satisfied'],
  onSubmit,
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const totalSteps = 5;

  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const handleInputChange = (field: keyof SurveyData, value: string | string[]) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'name' && typeof value === 'string' && value.trim()) setErrors(p => ({ ...p, name: '' }));
    if (field === 'email' && typeof value === 'string' && validateEmail(value)) setErrors(p => ({ ...p, email: '' }));
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFormData((prev) => ({
      ...prev,
      features: checked ? [...prev.features, feature] : prev.features.filter(f => f !== feature)
    }));
  };

  const isStepValid = useMemo(() => {
    if (currentStep === 1) return formData.name.trim().length > 0 && validateEmail(formData.email);
    if (currentStep === 2) return formData.satisfaction !== '';
    return true;
  }, [currentStep, formData]);

  const handleNext = () => {
    if (currentStep === 1) {
      if (!formData.name.trim() || !validateEmail(formData.email)) {
        setErrors({
          name: !formData.name.trim() ? 'Name required' : '',
          email: !validateEmail(formData.email) ? 'Valid email required' : ''
        });
        return;
      }
    }
    if (currentStep < totalSteps) setCurrentStep(currentStep + 1);
  };

  const renderStep = () => {
    switch (currentStep) {
      case 1:
        return (
          <Stack gap={20}>
            <Heading level={3}>Your Info</Heading>
            <FormField label="Full Name" required error={errors.name}>
              <Input label="Full Name" value={formData.name} onChange={v => handleInputChange('name', v)} placeholder="John Doe" />
            </FormField>
            <FormField label="Email Address" required error={errors.email}>
              <Input label="Email Address" type="email" value={formData.email} onChange={v => handleInputChange('email', v)} placeholder="john@example.com" />
            </FormField>
          </Stack>
        );
      case 2:
        return (
          <Stack gap={20}>
            <Heading level={3}>Satisfaction</Heading>
            <RadioGroup
              label="How satisfied are you?"
              value={formData.satisfaction}
              onChange={v => handleInputChange('satisfaction', v)}
              options={satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: l }))}
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={20}>
            <Heading level={3}>Interests</Heading>
            <Stack gap={12}>
              {featureOptions.map(opt => (
                <Checkbox key={opt} label={opt} checked={formData.features.includes(opt)} onChange={c => handleFeatureToggle(opt, c)} />
              ))}
            </Stack>
          </Stack>
        );
      case 4:
        return (
          <Stack gap={20}>
            <Heading level={3}>Comments</Heading>
            <TextArea label="Any feedback?" value={formData.comments} onChange={v => handleInputChange('comments', v)} maxLength={500} showCount rows={5} />
          </Stack>
        );
      case 5:
        return (
          <Stack gap={24}>
            <Heading level={3}>Review</Heading>
            <Stack gap={12}>
              <Box padding={12} background="var(--ggui-color-surfaceVariant)" borderRadius={8}>
                <Text variant="label">User: {formData.name} ({formData.email})</Text>
              </Box>
              <Box padding={12} background="var(--ggui-color-surfaceVariant)" borderRadius={8}>
                <Text variant="label">Rating: {satisfactionLabels[parseInt(formData.satisfaction) - 1]}</Text>
              </Box>
              <Box padding={12} background="var(--ggui-color-surfaceVariant)" borderRadius={8}>
                <Stack direction="horizontal" gap={8} wrap>
                  {formData.features.map(f => <Badge key={f} variant="primary">{f}</Badge>)}
                </Stack>
              </Box>
            </Stack>
          </Stack>
        );
      default: return null;
    }
  };

  return (
    <Container maxWidth="md" padding={20}>
      <Card padding={32} radius="lg" shadow="md">
        <Stack gap={24}>
          <Stack gap={8}>
            <Text variant="caption">Step {currentStep} of {totalSteps}</Text>
            <Progress value={currentStep} max={totalSteps} />
          </Stack>
          <Box style={{ minHeight: 300 }}>{renderStep()}</Box>
          <Divider />
          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onPress={() => setCurrentStep(s => Math.max(1, s - 1))} disabled={currentStep === 1}>Back</Button>
            {currentStep === totalSteps ? (
              <Button variant="primary" onPress={() => onSubmit && onSubmit(formData)}>Submit</Button>
            ) : (
              <Button variant="primary" onPress={handleNext} disabled={!isStepValid}>Next</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Text,
  Card,
  Heading,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<ElementData>;
}

const getCategoryColors = (category: string = 'unknown') => {
  const cat = category.toLowerCase();
  if (cat.includes('alkali metal')) return { bg: 'var(--ggui-color-error-100)', text: 'var(--ggui-color-error-800)', border: 'var(--ggui-color-error-300)' };
  if (cat.includes('alkaline earth')) return { bg: 'var(--ggui-color-warning-100)', text: 'var(--ggui-color-warning-800)', border: 'var(--ggui-color-warning-300)' };
  if (cat.includes('transition metal')) return { bg: 'var(--ggui-color-warning-50)', text: 'var(--ggui-color-warning-700)', border: 'var(--ggui-color-warning-200)' };
  if (cat.includes('lanthanide')) return { bg: 'var(--ggui-color-info-50)', text: 'var(--ggui-color-info-800)', border: 'var(--ggui-color-info-200)' };
  if (cat.includes('actinide')) return { bg: 'var(--ggui-color-info-100)', text: 'var(--ggui-color-info-800)', border: 'var(--ggui-color-info-300)' };
  if (cat.includes('post-transition')) return { bg: 'var(--ggui-color-success-50)', text: 'var(--ggui-color-success-800)', border: 'var(--ggui-color-success-200)' };
  if (cat.includes('metalloid')) return { bg: 'var(--ggui-color-success-100)', text: 'var(--ggui-color-success-900)', border: 'var(--ggui-color-success-300)' };
  if (cat.includes('nonmetal')) return { bg: 'var(--ggui-color-success-200)', text: 'var(--ggui-color-success-900)', border: 'var(--ggui-color-success-400)' };
  if (cat.includes('noble gas')) return { bg: 'var(--ggui-color-primary-100)', text: 'var(--ggui-color-primary-800)', border: 'var(--ggui-color-primary-300)' };
  return { bg: 'var(--ggui-color-neutral-100)', text: 'var(--ggui-color-neutral-700)', border: 'var(--ggui-color-neutral-300)' };
};

export default function PeriodicTable(props: Props) {
  const elements = props.elements || [];
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach(el => { if (el.category) set.add(el.category); });
    return Array.from(set).sort();
  }, [elements]);

  const filteredElements = useMemo(() => {
    const q = search.toLowerCase();
    return elements.map(el => ({
      ...el,
      isVisible: !q || (el.name || '').toLowerCase().includes(q) || (el.symbol || '').toLowerCase().includes(q)
    }));
  }, [elements, search]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        <Stack direction="horizontal" justify="between" align="end" wrap gap="var(--ggui-spacing-4, 16px)">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={1}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Properties of chemical elements.</Text>
          </Stack>
          <Box style={{ minWidth: '300px' }}>
            <SearchField
              placeholder="Search elements..."
              value={search}
              onChange={setSearch}
              size="md"
            />
          </Box>
        </Stack>

        <Box padding={12} borderRadius="var(--ggui-shape-radius-md, 8px)" style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap justify="start">
            {categories.map(cat => (
              <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-1, 4px)">
                <Box borderRadius="var(--ggui-shape-radius-sm, 4px)" style={{ width: '12px', height: '12px', backgroundColor: getCategoryColors(cat).bg, border: `1px solid ${getCategoryColors(cat).border}` }} />
                <Text variant="caption">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Box>

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-6, 24px)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(64px, 1fr))', gap: 'var(--ggui-spacing-1, 4px)', minWidth: '1152px' }}>
            {filteredElements.map((el) => {
              const colors = getCategoryColors(el.category);
              const active = selected && selected.atomicNumber === el.atomicNumber;
              return (
                <div key={el.atomicNumber} onClick={() => setSelected(el)} role="button" tabIndex={0} onKeyDown={e => { if (e.key==='Enter'||e.key===' ') setSelected(el); }} style={{ gridRow: el.row, gridColumn: el.col, cursor: 'pointer', transition: 'transform 200ms ease, opacity 200ms ease', opacity: el.isVisible ? 1 : 0.25, transform: active ? 'scale(1.1)' : 'none', zIndex: active ? 10 : 1 }}>
                  <Box borderRadius="var(--ggui-shape-radius-sm, 4px)" padding={4} style={{ backgroundColor: colors.bg, color: colors.text, border: active ? '2px solid var(--ggui-color-primary-600)' : `1px solid ${colors.border}`, aspectRatio: '1/1', width: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', position: 'relative', boxShadow: active ? 'var(--ggui-shape-shadow-lg)' : 'none' }}>
                    <Text style={{ position: 'absolute', top: '2px', left: '4px', fontSize: '10px', fontWeight: 'bold' }}>{el.atomicNumber}</Text>
                    <Text style={{ fontSize: 'var(--ggui-font-size-xl)', fontWeight: 'bold', lineHeight: 1 }}>{el.symbol}</Text>
                    <Text truncate style={{ fontSize: '9px', marginTop: '2px', maxWidth: '100%', textAlign: 'center' }}>{el.name}</Text>
                  </Box>
                </div>
              );
            })}
          </div>
        </Box>

        {selected ? (
          <Card padding="var(--ggui-spacing-8, 32px)" shadow="lg" radius="xl" border>
            <Stack direction="horizontal" justify="between" align="start" wrap gap="var(--ggui-spacing-8, 32px)">
              <Stack gap="var(--ggui-spacing-6, 24px)" style={{ flex: '2 1 400px' }}>
                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-6, 24px)">
                  <Box padding="var(--ggui-spacing-6, 24px)" borderRadius="var(--ggui-shape-radius-lg, 12px)" style={{ backgroundColor: getCategoryColors(selected.category).bg, border: `3px solid ${getCategoryColors(selected.category).border}`, minWidth: '100px', textAlign: 'center' }}>
                    <Heading level={1} color={getCategoryColors(selected.category).text}>{selected.symbol}</Heading>
                  </Box>
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Heading level={1}>{selected.name}</Heading>
                    <div style={{ display: 'flex' }}><Badge variant="primary" size="lg">{selected.category || 'Element'}</Badge></div>
                  </Stack>
                </Stack>
                <Text variant="bodyLarge" color="var(--ggui-color-neutral-700, #374151)" style={{ maxWidth: '60ch' }}>
                  {selected.name} is a {selected.category} element with atomic number {selected.atomicNumber} and symbol {selected.symbol}. Standard weight: {selected.atomicWeight} u.
                </Text>
              </Stack>
              <Box style={{ flex: '1 1 280px', backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', padding: 'var(--ggui-spacing-8, 32px)', border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Stack direction="horizontal" justify="between"><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text><Text variant="body" weight="bold">{selected.atomicNumber}</Text></Stack>
                  <Divider margin="var(--ggui-spacing-1, 4px)" />
                  <Stack direction="horizontal" justify="between"><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text><Text variant="body" weight="bold">{selected.atomicWeight}</Text></Stack>
                  <Divider margin="var(--ggui-spacing-1, 4px)" />
                  <Stack direction="horizontal" justify="between"><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Position</Text><Text variant="body" weight="bold">R{selected.row} C{selected.col}</Text></Stack>
                </Stack>
              </Box>
            </Stack>
          </Card>
        ) : (
          <Box padding={48} borderRadius="var(--ggui-shape-radius-lg, 12px)" style={{ border: '2px dashed var(--ggui-color-outline, #d4d4d8)', textAlign: 'center' }}>
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Select an element to view properties.</Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Box,
  Stack,
  Heading,
  Badge,
  Text,
  Input,
  Button,
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Message[];
  /** Send Message Action */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface Component
 */
export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages: initialMessages, sendMessage } = props;

  const [inputText, setInputText] = useState('');
  const [localMessages, setLocalMessages] = useState<Message[]>(initialMessages || []);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (initialMessages) setLocalMessages(initialMessages);
  }, [initialMessages]);

  useEffect(() => {
    if (messagesEndRef.current) messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [localMessages]);

  useEffect(() => {
    const handler = (e: any) => {
      const data = e.detail;
      if (data) {
        setLocalMessages(prev => [...prev, {
          sender: data.sender || 'Assistant',
          text: data.text || '',
          timestamp: data.timestamp || new Date().toISOString()
        }]);
      }
    };
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handler);
    }
    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener('ggui:agent-data', handler);
      }
    };
  }, []);

  const handleSend = () => {
    const text = inputText.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    if (sendMessage) sendMessage({ text, timestamp });
    setLocalMessages(prev => [...prev, { sender: currentUser, text, timestamp }]);
    setInputText('');
  };

  return (
    <Card padding={0} shadow="sm" radius="lg" border style={{ display: 'flex', flexDirection: 'column', height: '600px', backgroundColor: 'var(--ggui-color-surface)', overflow: 'hidden' }}>
      <Box padding={16} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{title}</Heading>
          {participantCount !== undefined && <Badge variant="secondary" pill>{participantCount}</Badge>}
        </Stack>
      </Box>

      <Box padding={16} style={{ flex: 1, overflowY: 'auto' }}>
        <div role="log" aria-live="polite">
          <Stack gap={16}>
            {localMessages.map((m, i) => {
              const isMe = m.sender === currentUser;
              const isG = i > 0 && localMessages[i-1].sender === m.sender;
              return (
                <Stack key={i} direction="horizontal" justify={isMe ? 'end' : 'start'}>
                  <Stack direction="vertical" gap={4} style={{ maxWidth: '80%' }}>
                    {!isG && <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)" align={isMe ? 'right' : 'left'}>{m.sender}</Text>}
                    <Box paddingX={12} paddingY={8} background={isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'} borderRadius={12} style={{ borderBottomRightRadius: isMe ? '2px' : '12px', borderBottomLeftRadius: !isMe ? '2px' : '12px' }}>
                      <Text variant="body" color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface)'}>{m.text}</Text>
                    </Box>
                    <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant)" align={isMe ? 'right' : 'left'}>{m.timestamp ? new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}</Text>
                  </Stack>
                </Stack>
              );
            })}
            <div ref={messagesEndRef} />
          </Stack>
        </div>
      </Box>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" gap={12} align="end">
          <div style={{ flex: 1 }} onKeyDown={(e) => { if (e.key === 'Enter') handleSend(); }}>
            <Text variant="label" size="xs" as="p">Message</Text>
            <Input label="Message" value={inputText} onChange={setInputText} placeholder="Type a message..." />
          </div>
          <Button variant="primary" disabled={!inputText.trim()} onClick={handleSend} aria-label="Send" style={{ marginBottom: '4px' }}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Box,
  Icon,
  Spinner,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard: A real-time market monitoring interface.
 * Listens for agent-driven data streams to update prices dynamically.
 */
export default function StockTickerDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  const [liveData, setLiveData] = useState<Stock[]>(initialStocks);
  const [timestamp, setTimestamp] = useState<string | undefined>(initialLastUpdated);

  // Sync props to state if they change externally (Standard Props Contract)
  useEffect(() => {
    if (initialStocks && initialStocks.length > 0) {
      setLiveData(initialStocks);
    }
  }, [initialStocks]);

  useEffect(() => {
    if (initialLastUpdated) {
      setTimestamp(initialLastUpdated);
    }
  }, [initialLastUpdated]);

  // Stream Contract: Listen for live updates from the agent
  // We use the global event listener to catch 'ggui:agent-data' broadcasts.
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event?.detail;
      if (data?.stocks) {
        setLiveData(data.stocks);
      }
      if (data?.lastUpdated) {
        setTimestamp(data.lastUpdated);
      }
    };

    // Attach to the global scope to catch events broadcasted by the agent
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleAgentData);
      return () => removeEventListener('ggui:agent-data', handleAgentData);
    }
  }, []);

  const formattedTime = timestamp
    ? new Date(timestamp).toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      })
    : '--:--:--';

  // Loading State: Render if no data is available yet
  if (!liveData || liveData.length === 0) {
    return (
      <Container maxWidth="xl" padding={24}>
        <Stack align="center" justify="center" gap={16} style={{ minHeight: '300px' }}>
          <Spinner size={40} color="var(--ggui-color-primary-600)" />
          <Text color="var(--ggui-color-onSurfaceVariant)">
            Connecting to live market data stream...
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack
          direction="horizontal"
          justify="between"
          align="end"
          wrap
          gap={12}
        >
          <Heading level={2}>Market Watch</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Last Updated: {formattedTime}
          </Text>
        </Stack>

        {/* Grid of Stock Cards */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {liveData.map((stock, index) => {
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const isPositive = change > 0;
            const isNegative = change < 0;

            let statusColor = 'var(--ggui-color-onSurfaceVariant)';
            let borderColor = 'var(--ggui-color-outline)';
            let iconName: 'chevron-up' | 'chevron-down' | undefined = undefined;

            if (isPositive) {
              statusColor = 'var(--ggui-color-success-600)';
              borderColor = 'var(--ggui-color-success-500)';
              iconName = 'chevron-up';
            } else if (isNegative) {
              statusColor = 'var(--ggui-color-error-600)';
              borderColor = 'var(--ggui-color-error-500)';
              iconName = 'chevron-down';
            }

            const displayPrice = Number(stock.price ?? 0).toFixed(2);
            const displayChange = `${isPositive ? '+' : ''}${change.toFixed(2)}`;
            const displayPercent = `${isPositive ? '+' : ''}${changePercent.toFixed(2)}%`;

            return (
              <Box
                key={stock.symbol || `stock-${index}`}
                padding={16}
                borderRadius="var(--ggui-shape-radius-lg)"
                background="var(--ggui-color-surfaceVariant)"
                style={{
                  border: `1px solid ${borderColor}`,
                  boxShadow: 'var(--ggui-shape-shadow-sm)',
                  transition: 'all 200ms ease-in-out',
                  position: 'relative',
                }}
              >
                <Stack direction="horizontal" justify="between" align="start">
                  {/* Left Side: Symbol and Name */}
                  <Stack gap={4} style={{ overflow: 'hidden', flex: 1 }}>
                    <Text
                      size="xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface)"
                      truncate
                      as="span"
                    >
                      {stock.symbol || '---'}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant)"
                      truncate
                      as="span"
                    >
                      {stock.name || 'Company Name'}
                    </Text>
                  </Stack>

                  {/* Right Side: Price and Change Stats */}
                  <Stack gap={4} align="end">
                    <Text
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface)"
                      as="span"
                    >
                      ${displayPrice}
                    </Text>
                    <Stack direction="horizontal" gap={4} align="center">
                      {iconName && (
                        <Icon
                          name={iconName}
                          size={16}
                          color={statusColor}
                          aria-hidden="true"
                        />
                      )}
                      <Text
                        variant="label"
                        color={statusColor}
                        weight="semibold"
                        as="span"
                      >
                        {displayChange} ({displayPercent})
                      </Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Box>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Stack,
  Text,
  Heading,
  Card,
  Input,
  Select,
  Divider,
  Toggle,
  RadioGroup,
  Box,
  Spacer,
  Button,
  Progress,
  Icon
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete: (data: any) => void;
}

export default function OnboardingWizard(props: Props) {
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name || '');
  const [email, setEmail] = useState(props.initialProfile?.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile?.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme || 'light');
  const [emailError, setEmailError] = useState<string | undefined>(undefined);

  const handleNext = () => {
    if (step === 1) {
      if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
        setEmailError('Invalid email');
        return;
      }
      setEmailError(undefined);
    }
    setStep(s => s + 1);
  };

  const handleComplete = () => {
    props.onComplete({ name, email, avatar, role, emailNotifications, theme });
  };

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="end">
            <Heading level={2}>
              {step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm'}
            </Heading>
            <Text variant="bodySmall">Step {step}/3</Text>
          </Stack>
          <Progress value={(step / 3) * 100} />
        </Stack>

        <Card shadow="md" padding={32} radius="lg">
          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {step === 1 && (
              <Stack gap={24}>
                <Input label="Name" required value={name} onChange={setName} placeholder="Jane Doe" id="n1" />
                <Input label="Email" required type="email" value={email} onChange={setEmail} error={emailError} placeholder="jane@example.com" id="e1" />
                <Stack gap={12}>
                  <Text variant="label">Choose Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {props.avatarOptions.map(emoji => (
                      <Button key={emoji} variant={avatar === emoji ? 'primary' : 'outline'} onPress={() => setAvatar(emoji)} size="lg">
                        {emoji}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Select label="Role" required value={role} onChange={setRole} options={props.roleOptions.map(r => ({ value: r, label: r }))} placeholder="Select a role..." id="s1" />
                <Divider />
                <Toggle label="Email Notifications" checked={emailNotifications} onChange={setEmailNotifications} size="md" />
                <Divider />
                <RadioGroup label="Theme" value={theme} onChange={setTheme} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
                  <Stack gap={16}>
                    <Text variant="label" color="var(--ggui-color-primary-600)">Profile Review</Text>
                    <Stack gap={8}>
                      <Text variant="bodySmall">Name: {name}</Text>
                      <Text variant="bodySmall">Email: {email}</Text>
                      <Text variant="bodySmall">Avatar: {avatar}</Text>
                      <Divider />
                      <Text variant="bodySmall">Role: {role}</Text>
                      <Text variant="bodySmall">Notifications: {emailNotifications ? 'On' : 'Off'}</Text>
                      <Text variant="bodySmall">Theme: {theme}</Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Spacer size={32} />
          <Divider margin={0} />
          <Spacer size={16} />

          <Stack direction="horizontal" justify="between" align="center">
            <Button variant="ghost" disabled={step === 1} onPress={() => setStep(step - 1)}>Back</Button>
            {step < 3 ? (
              <Button variant="primary" onPress={handleNext} disabled={(step === 1 && (!name || !email)) || (step === 2 && !role)}>Next</Button>
            ) : (
              <Button variant="primary" onPress={handleComplete}>Finish</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
import {
