      'var(--ggui-color-warning-700, #b45309)',
      'var(--ggui-color-warning-900, #78350f)',
    ],
    'non-metal': [
      'var(--ggui-color-neutral-50, #f9fafb)',
      'var(--ggui-color-neutral-300, #d1d5db)',
      'var(--ggui-color-neutral-700, #374151)',
      'var(--ggui-color-onSurface, #18181b)',
    ],
    metalloid: [
      'var(--ggui-color-primary-50, #f0f9ff)',
      'var(--ggui-color-primary-300, #7dd3fc)',
      'var(--ggui-color-primary-700, #0369a1)',
      'var(--ggui-color-primary-900, #0c4a6e)',
    ],
    'post-transition-metal': [
      'var(--ggui-color-primary-50, #f0f9ff)',
