import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Heading,
  Badge,
  Box,
  Text,
  Input,
  Button,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message action - called when user sends a message */
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface MessageGroup {
  sender?: string;
  messages: Message[];
}

// Helper to format timestamp as HH:MM
const formatTime = (isoString?: string): string => {
  if (!isoString) return '';
  try {
    const date = new Date(isoString);
    return date.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: false,
    });
  } catch {
    return '';
  }
};

// Helper to group consecutive messages by sender
const groupMessages = (messages: Message[]): MessageGroup[] => {
  if (!messages.length) return [];

  const groups: MessageGroup[] = [];
  let currentGroup: MessageGroup | null = null;

  messages.forEach((msg) => {
    if (!currentGroup || currentGroup.sender !== msg.sender) {
      currentGroup = {
        sender: msg.sender,
        messages: [msg],
      };
      groups.push(currentGroup);
    } else {
      currentGroup.messages.push(msg);
    }
  });

  return groups;
};

export default function GeneratedComponent({
  title,
  currentUser,
  participantCount = 0,
  messages,
  onSendMessage,
}: Props) {
  const [inputText, setInputText] = useState('');
  const messageEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on mount and when messages change
  useEffect(() => {
    messageEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = () => {
    const trimmedText = inputText.trim();
    if (trimmedText.length === 0) return;

    onSendMessage({
      text: trimmedText,
      timestamp: new Date().toISOString(),
    });

    setInputText('');
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const messageGroups = groupMessages(messages);
  const isCurrentUser = (sender?: string) => sender === currentUser;
  const isSendDisabled = inputText.trim().length === 0;

  return (
    <Card
      shadow="sm"
      padding={0}
      radius="lg"
      border={true}
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
      }}
    >
      {/* Header */}
      <Box
        paddingX={16}
        paddingY={12}
        borderRadius={0}
        background="var(--ggui-color-surface, #fafafa)"
        style={{
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={4}>{title}</Heading>
          {participantCount !== undefined && participantCount > 0 && (
            <Badge variant="primary" size="sm" pill={true}>
              {participantCount} participant{participantCount !== 1 ? 's' : ''}
            </Badge>
          )}
        </Stack>
      </Box>

      {/* Message List */}
      <Box
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <Stack gap={12} direction="vertical">
          {messageGroups.length === 0 ? (
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
            >
              No messages yet. Start the conversation!
            </Text>
          ) : (
            messageGroups.map((group, groupIndex) => (
              <Stack
                key={groupIndex}
                gap={8}
                direction="vertical"
                align={isCurrentUser(group.sender) ? 'end' : 'start'}
              >
                {/* Sender name (only show on first message of group) */}
                {group.sender && (
                  <Text
                    variant="label"
                    size="xs"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {group.sender}
                  </Text>
                )}

                {/* Message bubbles */}
                <Stack
                  gap={4}
                  direction="vertical"
                  align={isCurrentUser(group.sender) ? 'end' : 'start'}
                >
                  {group.messages.map((msg, msgIndex) => {
                    const isOwn = isCurrentUser(msg.sender);
                    const isLastInGroup = msgIndex === group.messages.length - 1;

                    return (
                      <Box
                        key={msgIndex}
                        padding={12}
                        borderRadius={8}
                        background={
                          isOwn
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                        }
                        style={{
                          maxWidth: '70%',
                          wordWrap: 'break-word',
                        }}
                      >
                        <Text
                          variant="body"
                          color={
                            isOwn
                              ? 'var(--ggui-color-primary-50, #f0f9ff)'
                              : 'var(--ggui-color-onSurface, #18181b)'
                          }
                        >
                          {msg.text}
                        </Text>

                        {/* Timestamp on last message of group */}
                        {isLastInGroup && msg.timestamp && (
                          <Text
                            variant="caption"
                            size="xs"
                            color={
                              isOwn
                                ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                            style={{
                              marginTop: 'var(--ggui-spacing-1, 4px)',
                            }}
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        )}
                      </Box>
                    );
                  })}
                </Stack>
              </Stack>
            ))
          )}
          <div ref={messageEndRef} />
        </Stack>
      </Box>

      {/* Divider */}
      <Divider
        orientation="horizontal"
        margin={0}
        color="var(--ggui-color-outline, #d4d4d8)"
      />

      {/* Input Area */}
      <Box paddingX={16} paddingY={12} background="var(--ggui-color-surface, #fafafa)">
        <Stack direction="horizontal" gap={8} align="center">
          <div style={{ flex: 1 }}>
            <label style={{ display: 'none' }}>Message</label>
            <Input
              label="Compose message"
              placeholder="Type a message..."
              value={inputText}
              onChange={setInputText}
              size="md"
              onKeyPress={handleKeyPress}
            />
          </div>
          <Button
            variant="primary"
            size="md"
            onClick={handleSendMessage}
            disabled={isSendDisabled}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Box,
  Card,
  Icon,
  Spinner,
  Alert,
} from '@ggui-ai/design/primitives';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: StockData[];
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  const [displayStocks, setDisplayStocks] = useState<StockData[]>(stocks);
  const [lastUpdated, setLastUpdated] = useState<string>(
    initialLastUpdated || new Date().toISOString()
  );
  const [connectionStatus, setConnectionStatus] = useState<
    'idle' | 'connecting' | 'connected' | 'reconnecting' | 'error'
  >('connected');
  const [lastError, setLastError] = useState<string | null>(null);

  // Update when props change
  useEffect(() => {
    if (stocks && stocks.length > 0) {
      setDisplayStocks(stocks);
      setConnectionStatus('connected');
      if (initialLastUpdated) {
        setLastUpdated(initialLastUpdated);
      }
    }
  }, [stocks, initialLastUpdated]);

  // Format timestamp for display
  const formatTimestamp = (isoString: string): string => {
    try {
      const date = new Date(isoString);
      const now = new Date();
      const diffMs = now.getTime() - date.getTime();
      const diffMins = Math.floor(diffMs / 60000);
      const diffSecs = Math.floor(diffMs / 1000);

      if (diffMins > 0)
        return `Updated ${diffMins} minute${diffMins > 1 ? 's' : ''} ago`;
      if (diffSecs > 0)
        return `Updated ${diffSecs} second${diffSecs > 1 ? 's' : ''} ago`;
      return 'Updated just now';
    } catch {
      return 'Last updated: unknown time';
    }
  };

  // Determine change color and arrow
  const getChangeStyles = (changePercent?: number) => {
    if (changePercent === undefined || changePercent === 0) {
      return {
        color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
        arrow: null,
        bgColor: 'transparent',
      };
    }
    if (changePercent > 0) {
      return {
        color: 'var(--ggui-color-success-600, #16a34a)',
        arrow: 'chevron-up',
        bgColor: 'var(--ggui-color-success-100, #dcfce7)',
      };
    }
    return {
      color: 'var(--ggui-color-error-600, #dc2626)',
      arrow: 'chevron-down',
      bgColor: 'var(--ggui-color-error-100, #fee2e2)',
    };
  };

  const isLoading = connectionStatus === 'connecting';
  const isReconnecting = connectionStatus === 'reconnecting';
  const isError = connectionStatus === 'error';
  const isEmpty = displayStocks.length === 0 && connectionStatus === 'connected';

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={20} direction="vertical">
        {/* Header Section */}
        <Stack gap={8} direction="vertical">
          <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Heading>
          <Text
            variant="bodySmall"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {formatTimestamp(lastUpdated)}
          </Text>
        </Stack>

        {/* Status Alerts */}
        {isLoading && (
          <Alert variant="info" title="Connecting to Market Data">
            <Stack direction="horizontal" gap={12} align="center">
              <Spinner
                size={20}
                color="var(--ggui-color-primary-600, #0284c7)"
              />
              <Text
                variant="body"
                color="var(--ggui-color-info-800, #155e75)"
              >
                Loading live stock data...
              </Text>
            </Stack>
          </Alert>
        )}

        {isReconnecting && (
          <Alert variant="warning" title="Reconnecting">
            Attempting to reconnect to market data. Using last known prices.
          </Alert>
        )}

        {isError && lastError && (
          <Alert
            variant="error"
            title="Data Error"
            closable
            onClose={() => setLastError(null)}
          >
            {lastError}
          </Alert>
        )}

        {isEmpty && (
          <Alert variant="info">
            No stocks available. Waiting for market data...
          </Alert>
        )}

        {/* Stock Grid */}
        {!isLoading && (
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
              opacity: isReconnecting ? 0.7 : 1,
              transition: 'opacity 200ms ease-in-out',
            }}
          >
            {displayStocks.map((stock, index) => {
              const changeStyles = getChangeStyles(stock.changePercent);
              const cardStyle =
                changeStyles.bgColor !== 'transparent'
                  ? {
                      backgroundColor: changeStyles.bgColor,
                      borderColor: changeStyles.color,
                    }
                  : {};

              return (
                <Card
                  key={stock.symbol || index}
                  shadow="sm"
                  border={true}
                  radius="lg"
                  padding={16}
                  style={{
                    ...cardStyle,
                    animation: `ggui-fadeIn 200ms ease-out ${index * 50}ms both`,
                    transition:
                      'box-shadow 200ms ease-in-out, background-color 200ms ease-in-out',
                  }}
                >
                  <Stack gap={12} direction="vertical">
                    {/* Ticker Symbol */}
                    <Heading
                      level={3}
                      color="var(--ggui-color-onSurface, #18181b)"
                      style={{
                        fontSize: 'var(--ggui-font-size-xl, 20px)',
                        fontWeight: 'var(--ggui-font-weight-bold, 700)',
                      }}
                    >
                      {stock.symbol || 'N/A'}
                    </Heading>

                    {/* Company Name */}
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                    >
                      {stock.name || 'Unknown Company'}
                    </Text>

                    {/* Price */}
                    <Text
                      variant="bodyLarge"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      style={{
                        fontSize: 'var(--ggui-font-size-lg, 18px)',
                      }}
                    >
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>

                    {/* Change & Arrow */}
                    {stock.changePercent !== undefined && (
                      <Stack direction="horizontal" gap={4} align="center">
                        {changeStyles.arrow && (
                          <Icon
                            name={changeStyles.arrow}
                            size={16}
                            color={changeStyles.color}
                          />
                        )}
                        <Text
                          variant="label"
                          color={changeStyles.color}
                          weight="medium"
                        >
                          {stock.change !== undefined && stock.change >= 0
                            ? '+'
                            : ''}
                          {(stock.change ?? 0).toFixed(2)}
                          {' '}
                          ({stock.changePercent >= 0 ? '+' : ''}
                          {(stock.changePercent ?? 0).toFixed(2)}%)
                        </Text>
                      </Stack>
                    )}
                  </Stack>
                </Card>
              );
            })}
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Progress,
  Badge,
  Button,
  Input,
  Select,
  Toggle,
  Box,
  Divider,
  Spacer,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (profileData: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard({
  initialProfile,
  avatarOptions,
  roleOptions,
  onComplete,
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar:
      initialProfile?.avatar || (avatarOptions.length > 0 ? avatarOptions[0] : ''),
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const [errors, setErrors] = useState({
    name: '',
    email: '',
    role: '',
  });

  const validateEmail = (email: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const validateStep = (step: number): boolean => {
    const newErrors = { name: '', email: '', role: '' };

    if (step === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
      } else if (formData.name.trim().length < 2) {
        newErrors.name = 'Name must be at least 2 characters';
      } else if (formData.name.length > 50) {
        newErrors.name = 'Name must be 50 characters or less';
      }

      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!validateEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
    }

    if (step === 2) {
      if (!formData.role) {
        newErrors.role = 'Role is required';
      } else if (!roleOptions.includes(formData.role)) {
        newErrors.role = 'Please select a valid role';
      }
    }

    setErrors(newErrors);
    return Object.values(newErrors).every((err) => !err);
  };

  const isStep1Valid = (): boolean => {
    return (
      formData.name.trim().length >= 2 &&
      formData.name.length <= 50 &&
      validateEmail(formData.email)
    );
  };

  const isStep2Valid = (): boolean => {
    return formData.role && roleOptions.includes(formData.role);
  };

  const handleNext = () => {
    if (validateStep(currentStep)) {
      if (currentStep < 3) {
        setCurrentStep(currentStep + 1);
        setErrors({ name: '', email: '', role: '' });
      }
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({ name: '', email: '', role: '' });
    }
  };

  const handleComplete = () => {
    if (onComplete) {
      onComplete(formData);
    }
  };

  const progressValue = ((currentStep - 1) / 2) * 100;
  const isDarkTheme = formData.theme === 'dark';

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={16}>
        <Stack direction="horizontal" justify="between" align="center">
          <Badge variant="primary" size="md">
            Step {currentStep} of 3
          </Badge>
        </Stack>

        <Progress value={progressValue} max={100} variant="default" size="md" />

        <Divider margin={16} />

        {currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={2} align="center">
                Create Your Profile
              </Heading>

              <Input
                label="Full Name"
                placeholder="Enter your name"
                value={formData.name}
                onChange={(value) => setFormData({ ...formData, name: value })}
                error={errors.name}
                required
              />

              <Input
                label="Email"
                type="email"
                placeholder="your@email.com"
                value={formData.email}
                onChange={(value) => setFormData({ ...formData, email: value })}
                error={errors.email}
                helperText="We'll use this to send updates"
                required
              />

              <div>
                <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                  Choose Avatar
                </Text>
                <Stack
                  direction="horizontal"
                  gap={12}
                  align="center"
                  justify="center"
                >
                  {avatarOptions.map((emoji, idx) => (
                    <button
                      key={idx}
                      onClick={() => setFormData({ ...formData, avatar: emoji })}
                      style={{
                        width: '50px',
                        height: '50px',
                        fontSize: '24px',
                        border:
                          formData.avatar === emoji
                            ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                            : '2px solid var(--ggui-color-neutral-300, #d1d5db)',
                        background:
                          formData.avatar === emoji
                            ? 'var(--ggui-color-primary-50, #f0f9ff)'
                            : 'transparent',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                      }}
                    >
                      {emoji}
                    </button>
                  ))}
                </Stack>
              </div>
            </Stack>
          </Card>
        )}

        {currentStep === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={2} align="center">
                Set Your Preferences
              </Heading>

              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => setFormData({ ...formData, role: value })}
                options={roleOptions.map((role) => ({
                  value: role,
                  label: role,
                }))}
                placeholder="Select your role"
                error={errors.role}
                required
              />

              <Toggle
                label="Email Notifications"
                checked={formData.emailNotifications}
                onChange={(checked) =>
                  setFormData({
                    ...formData,
                    emailNotifications: checked,
                  })
                }
                size="md"
              />

              <Toggle
                label="Dark Theme"
                checked={isDarkTheme}
                onChange={(checked) =>
                  setFormData({
                    ...formData,
                    theme: checked ? 'dark' : 'light',
                  })
                }
                size="md"
              />
            </Stack>
          </Card>
        )}

        {currentStep === 3 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={2} align="center">
                Review Your Setup
              </Heading>

              <Stack gap={12}>
                <Text variant="label" weight="semibold">
                  Profile
                </Text>
                <Box paddingX={12} paddingY={8}>
                  <Stack gap={6}>
                    <Stack direction="horizontal" gap={8}>
                      <Text
                        variant="body"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        Name:
                      </Text>
                      <Text variant="body">{formData.name}</Text>
                    </Stack>
                    <Stack direction="horizontal" gap={8}>
                      <Text
                        variant="body"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        Email:
                      </Text>
                      <Text variant="body">{formData.email}</Text>
                    </Stack>
                    <Stack direction="horizontal" gap={8}>
                      <Text
                        variant="body"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        Avatar:
                      </Text>
                      <Text variant="body" size="lg">
                        {formData.avatar}
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>

              <Divider margin={12} />

              <Stack gap={12}>
                <Text variant="label" weight="semibold">
                  Preferences
                </Text>
                <Box paddingX={12} paddingY={8}>
                  <Stack gap={6}>
                    <Stack direction="horizontal" gap={8}>
                      <Text
                        variant="body"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        Role:
                      </Text>
                      <Text variant="body">{formData.role}</Text>
                    </Stack>
                    <Stack direction="horizontal" gap={8}>
                      <Text
                        variant="body"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        Notifications:
                      </Text>
                      <Text variant="body">
                        {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                      </Text>
                    </Stack>
                    <Stack direction="horizontal" gap={8}>
                      <Text
                        variant="body"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        Theme:
                      </Text>
                      <Text variant="body">
                        {isDarkTheme ? 'Dark' : 'Light'}
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>

              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
                align="center"
              >
                You can edit any information by clicking "Go Back"
              </Text>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" gap={8} justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            {currentStep === 3 ? 'Go Back' : 'Back'}
          </Button>

          <Spacer size="flex" />

          {currentStep < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid()) ||
                (currentStep === 2 && !isStep2Valid())
              }
            >
              Next
            </Button>
          )}

          {currentStep === 3 && (
            <Button variant="primary" onClick={handleComplete}>
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Box } from '@ggui-ai/design/primitives';

// --- Helper: map condition string to emoji ---
function getConditionEmoji(condition: string): string {
  const normalized = condition.toLowerCase().trim();
  if (normalized.includes('sunny') || normalized === 'clear') return '☀️';
  if (normalized.includes('partly cloudy') || normalized.includes('partly')) return '⛅';
  if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('rain')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '🌨️';
  if (normalized.includes('wind')) return '🌬️';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
  return '🌤️';
}

// --- Props interface (exact contract) ---
interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

