  const conditionEmoji = getConditionEmoji(condition);
  const unitLabel = unit === 'F' ? 'Fahrenheit' : 'Celsius';
  const unitSymbol = unit === 'F' ? '°F' : '°C';
  const speedUnit = unit === 'F' ? 'mph' : 'km/h';

  return (
    <div
