          padding={0}
          borderRadius="var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px) 0 0"
          background="linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-700, #0369a1))"
        >
          <Box paddingX={24} paddingY={24}>
            <Stack gap={12} align="start">
              {/* City name */}
              <Text
                variant="overline"
                color="var(--ggui-color-primary-100, #e0f2fe)"
                as="span"
              >
                {city}
              </Text>

              {/* Temperature + condition row */}
              <Stack direction="horizontal" align="center" gap={16}>
                {/* Large temperature display */}
                <Text
                  as="span"
                  size="4xl"
                  weight="bold"
                  color="var(--ggui-color-neutral-50, #f9fafb)"
                  aria-label={`${temperature} degrees ${unitLabel}`}
                >
                  {temperature}{unitSymbol}
                </Text>

                {/* Condition emoji + label */}
                <Stack gap={2} align="start">
                  <span aria-hidden="true" style={{ fontSize: 'var(--ggui-font-size-3xl, 30px)', lineHeight: 1 }}>
                    {conditionEmoji}
                  </span>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-primary-200, #bae6fd)"
                    as="span"
                  >
                    {condition}
                  </Text>
                </Stack>
              </Stack>

              {/* Stats row: humidity + wind speed */}
              <Stack direction="horizontal" gap={24}>
                {/* Humidity */}
                <div
                  aria-label={`Humidity ${humidity} percent`}
                  style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}
                >
                  <span aria-hidden="true" style={{ fontSize: 'var(--ggui-font-size-sm, 14px)' }}>💧</span>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-primary-200, #bae6fd)"
                    as="span"
                  >
                    {humidity}%
                  </Text>
                </div>

                {/* Wind speed */}
                <div
                  aria-label={`Wind speed ${windSpeed} ${speedUnit}`}
                  style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}
                >
                  <span aria-hidden="true" style={{ fontSize: 'var(--ggui-font-size-sm, 14px)' }}>💨</span>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-primary-200, #bae6fd)"
                    as="span"
                  >
                    {windSpeed} {speedUnit}
                  </Text>
                </div>
              </Stack>
            </Stack>
          </Box>
        </Box>

        {/* ── Forecast section ── */}
        <div
          aria-label="5-day forecast"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderRadius: '0 0 var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px)',
            padding: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          <Stack direction="horizontal" justify="between" gap={8}>
            {forecast.map((item, index) => (
              <div
                key={item.day ?? index}
                aria-label={`${item.day ?? 'Day'}: high ${item.high ?? '--'}°, low ${item.low ?? '--'}°`}
                style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)', flex: '1 1 0' }}
              >
                {/* Day name */}
                <Text
                  variant="caption"
                  weight="semibold"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="span"
                  align="center"
                >
                  {item.day ?? '—'}
                </Text>
                {/* Weather icon */}
                <span
                  aria-hidden="true"
                  style={{ fontSize: 'var(--ggui-font-size-xl, 20px)', lineHeight: 1.2 }}
                >
                  {item.icon ?? '🌤️'}
                </span>
                {/* High temp */}
                <Text
                  variant="label"
                  color="var(--ggui-color-onSurface, #18181b)"
                  as="span"
                  align="center"
                >
                  {item.high != null ? `${item.high}°` : '—'}
                </Text>
                {/* Low temp */}
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="span"
                  align="center"
                >
                  {item.low != null ? `${item.low}°` : '—'}
                </Text>
              </div>
            ))}
          </Stack>
        </div>
      </Card>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Stack, Box, Text, Heading, Card, Badge } from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

const CATEGORY_COLORS: Record<string, { bg: string; border: string; text: string }> = {
  'alkali metal':          { bg: 'var(--ggui-color-error-100, #fee2e2)',    border: 'var(--ggui-color-error-500, #ef4444)',    text: 'var(--ggui-color-error-700, #b91c1c)'    },
  'alkaline earth metal':  { bg: 'var(--ggui-color-warning-100, #fef3c7)', border: 'var(--ggui-color-warning-500, #f59e0b)',  text: 'var(--ggui-color-warning-700, #b45309)'  },
  'transition metal':      { bg: 'var(--ggui-color-primary-100, #e0f2fe)', border: 'var(--ggui-color-primary-500, #0ea5e9)', text: 'var(--ggui-color-primary-700, #0369a1)'  },
  'post-transition metal': { bg: 'var(--ggui-color-info-100, #cffafe)',    border: 'var(--ggui-color-info-500, #06b6d4)',    text: 'var(--ggui-color-info-700, #0e7490)'    },
  'metalloid':             { bg: 'var(--ggui-color-success-100, #dcfce7)', border: 'var(--ggui-color-success-500, #22c55e)', text: 'var(--ggui-color-success-700, #15803d)'  },
  'nonmetal':              { bg: 'var(--ggui-color-primary-50, #f0f9ff)',  border: 'var(--ggui-color-primary-300, #7dd3fc)', text: 'var(--ggui-color-primary-800, #075985)'  },
  'halogen':               { bg: 'var(--ggui-color-success-50, #f0fdf4)',  border: 'var(--ggui-color-success-600, #16a34a)', text: 'var(--ggui-color-success-800, #166534)'  },
  'noble gas':             { bg: 'var(--ggui-color-container, #ede9fe)',   border: 'var(--ggui-color-onContainer, #4c1d95)', text: 'var(--ggui-color-onContainer, #4c1d95)'  },
  'lanthanide':            { bg: 'var(--ggui-color-warning-50, #fffbeb)',  border: 'var(--ggui-color-warning-600, #d97706)', text: 'var(--ggui-color-warning-800, #92400e)'  },
  'actinide':              { bg: 'var(--ggui-color-error-50, #fef2f2)',    border: 'var(--ggui-color-error-400, #f87171)',   text: 'var(--ggui-color-error-800, #991b1b)'    },
};

const DEFAULT_COLORS = {
  bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  border: 'var(--ggui-color-outline, #d4d4d8)',
  text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
};

function getCategoryColors(category?: string) {
  if (!category) return DEFAULT_COLORS;
  return CATEGORY_COLORS[category.toLowerCase()] ?? DEFAULT_COLORS;
}

function formatAtomicWeight(w?: number): string {
  if (w == null) return '—';
  return w.toFixed(3);
}

export default function GeneratedComponent({ elements }: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filteredSet = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return new Set<number>();
    return new Set(
      elements
        .filter(el =>
          el.name?.toLowerCase().includes(q) ||
          el.symbol?.toLowerCase().includes(q)
        )
        .map(el => el.atomicNumber ?? -1)
    );
  }, [search, elements]);

  const isSearching = search.trim().length > 0;

  const categories = useMemo(() => {
    const seen = new Set<string>();
    const result: string[] = [];
    for (const el of elements) {
      if (el.category && !seen.has(el.category.toLowerCase())) {
        seen.add(el.category.toLowerCase());
        result.push(el.category);
      }
    }
    return result;
  }, [elements]);

  return (
    <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surface, #fafafa)">
      {/* Header */}
      <Stack gap={4} align="center">
        <Heading level={2} align="center" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Heading>
        <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Click any element to see details
        </Text>
      </Stack>

      {/* Search */}
      <Box paddingY="var(--ggui-spacing-4, 16px)">
        <div style={{ maxWidth: 360, margin: '0 auto' }}>
          <SearchField
