      </Box>

      {/* Legend */}
      <div
        role="list"
        aria-label="Element categories legend"
        style={{
          display: 'flex',
          flexWrap: 'wrap',
          gap: 'var(--ggui-spacing-2, 8px)',
          justifyContent: 'center',
          marginBottom: 'var(--ggui-spacing-4, 16px)',
        }}
      >
        {categories.map(cat => {
          const colors = getCategoryColors(cat);
          return (
            <div
              key={cat}
              role="listitem"
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-1, 4px)',
                padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                backgroundColor: colors.bg,
                border: `1px solid ${colors.border}`,
              }}
            >
              <Text variant="caption" color={colors.text} as="span">
                {cat}
              </Text>
            </div>
          );
        })}
      </div>

      {/* Periodic Table Grid */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
          gap: 'var(--ggui-spacing-1, 4px)',
          overflowX: 'auto',
          padding: 'var(--ggui-spacing-1, 4px) 0',
        }}
        role="grid"
        aria-label="Periodic table of elements"
      >
        {elements.map(el => {
          if (!el.row || !el.col) return null;
          const colors = getCategoryColors(el.category);
          const isMatch = !isSearching || filteredSet.has(el.atomicNumber ?? -1);
          const isSelected = selected?.atomicNumber === el.atomicNumber;

          return (
            <button
              key={el.atomicNumber ?? `${el.row}-${el.col}`}
              role="gridcell"
              aria-label={`${el.name ?? 'Unknown'}, symbol ${el.symbol ?? ''}, atomic number ${el.atomicNumber ?? ''}, category ${el.category ?? 'unknown'}`}
              aria-pressed={isSelected}
              onClick={() => setSelected(isSelected ? null : el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                backgroundColor: colors.bg,
                border: `1.5px solid ${isSelected ? colors.text : colors.border}`,
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                cursor: 'pointer',
                padding: 'var(--ggui-spacing-1, 4px) 2px',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                position: 'relative',
                minWidth: 44,
                minHeight: 52,
                opacity: isSearching && !isMatch ? 0.2 : 1,
                boxShadow: isSelected
                  ? `0 0 0 2px ${colors.text}`
                  : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                transition: 'all 150ms cubic-bezier(0.4, 0, 0.2, 1)',
                outline: 'none',
              }}
              onMouseEnter={e => {
                (e.currentTarget as HTMLButtonElement).style.transform = 'scale(1.15)';
                (e.currentTarget as HTMLButtonElement).style.zIndex = '10';
                (e.currentTarget as HTMLButtonElement).style.boxShadow = 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
              }}
              onMouseLeave={e => {
                (e.currentTarget as HTMLButtonElement).style.transform = 'scale(1)';
                (e.currentTarget as HTMLButtonElement).style.zIndex = '';
                (e.currentTarget as HTMLButtonElement).style.boxShadow = isSelected
                  ? `0 0 0 2px ${colors.text}`
                  : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))';
              }}
              onFocus={e => {
                (e.currentTarget as HTMLButtonElement).style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)';
                (e.currentTarget as HTMLButtonElement).style.outlineOffset = '2px';
              }}
              onBlur={e => {
                (e.currentTarget as HTMLButtonElement).style.outline = 'none';
              }}
            >
              {/* Atomic number top-left */}
              <span
                style={{
                  position: 'absolute',
                  top: 2,
                  left: 3,
                  fontSize: 'var(--ggui-font-size-xs, 12px)',
                  fontWeight: 'var(--ggui-font-weight-normal, 400)',
                  color: colors.text,
                  lineHeight: 1,
                }}
              >
                {el.atomicNumber}
              </span>
              {/* Symbol - large, centered */}
              <span
                style={{
                  fontSize: 'var(--ggui-font-size-base, 16px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: colors.text,
                  lineHeight: 1.2,
                  marginTop: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {el.symbol}
              </span>
              {/* Name truncated */}
              <span
                style={{
                  fontSize: 'var(--ggui-font-size-xs, 12px)',
                  color: colors.text,
                  opacity: 0.85,
                  lineHeight: 1,
                  maxWidth: '100%',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                  transform: 'scale(0.7)',
                  transformOrigin: 'center',
                }}
              >
                {el.name}
              </span>
            </button>
          );
        })}
      </div>

      {/* Detail Panel */}
      {selected && (
        <Box paddingY="var(--ggui-spacing-4, 16px)">
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Stack direction="horizontal" gap={16} align="center">
                {/* Element symbol block */}
                <div
                  style={{
                    width: 80,
                    height: 80,
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    backgroundColor: getCategoryColors(selected.category).bg,
                    border: `2px solid ${getCategoryColors(selected.category).border}`,
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexShrink: 0,
                  }}
                  aria-hidden="true"
                >
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: getCategoryColors(selected.category).text,
                      lineHeight: 1,
                    }}
                  >
                    {selected.atomicNumber}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-3xl, 30px)',
                      fontWeight: 'var(--ggui-font-weight-bold, 700)',
                      color: getCategoryColors(selected.category).text,
                      lineHeight: 1.1,
                    }}
                  >
                    {selected.symbol}
                  </span>
                </div>

                {/* Data fields */}
                <Stack gap={8}>
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
