                    <Stack gap={2}>
                      <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                      <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        {selected.atomicNumber ?? '—'}
