                    <Stack gap={2}>
                      <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                      <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        {selected.category ?? '—'}
                      </Text>
                    </Stack>
                  </div>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        </Box>
      )}
    </Box>
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Text, Heading, Badge, Input, Button } from '@ggui-ai/design/primitives';

interface MessageItem {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<MessageItem>;
  /** Action Contract: Send Message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

function formatTimestamp(iso?: string): string {
  if (!iso) return '';
  try {
    const date = new Date(iso);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return iso;
  }
}

function groupMessages(messages: MessageItem[]): MessageItem[][] {
  const groups: MessageItem[][] = [];
  let currentGroup: MessageItem[] = [];
  let currentSender: string | undefined = undefined;
  for (const msg of messages) {
    if (msg.sender === currentSender && currentGroup.length > 0) {
      currentGroup.push(msg);
    } else {
      if (currentGroup.length > 0) groups.push(currentGroup);
      currentGroup = [msg];
      currentSender = msg.sender;
    }
  }
  if (currentGroup.length > 0) groups.push(currentGroup);
  return groups;
}

function getAvatarColor(name: string): string {
  const colors = [
    'var(--ggui-color-primary-600, #0284c7)',
    'var(--ggui-color-success-600, #16a34a)',
    'var(--ggui-color-warning-600, #d97706)',
    'var(--ggui-color-error-600, #dc2626)',
  ];
  let hash = 0;
  for (let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
  return colors[Math.abs(hash) % colors.length];
}

export default function GeneratedComponent({
  title = 'Team Chat',
  currentUser = 'You',
  participantCount,
  messages = [
    { sender: 'Alice', text: "Hey everyone! How's the project going?", timestamp: '2025-01-15T10:00:00Z' },
    { sender: 'Alice', text: 'I just pushed the latest changes.', timestamp: '2025-01-15T10:00:30Z' },
    { sender: 'You', text: "Looks great! I'll review it now.", timestamp: '2025-01-15T10:01:00Z' },
    { sender: 'Bob', text: 'Nice work Alice! The new layout is much better.', timestamp: '2025-01-15T10:02:00Z' },
    { sender: 'You', text: 'Agreed, the improvements are solid.', timestamp: '2025-01-15T10:03:00Z' },
  ],
  onSendMessage,
}: Props) {
  const [inputValue, setInputValue] = useState('');
  const [streamMessages, setStreamMessages] = useState<MessageItem[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const allMessages = [...messages, ...streamMessages];

  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length, scrollToBottom]);

  // Stream Contract: ggui:agent-data
  useEffect(() => {
    const handler = (event: Event) => {
      const data = (event as CustomEvent).detail;
      if (data && typeof data === 'object') {
        setStreamMessages((prev) => [
          ...prev,
          {
            sender: data.sender || 'Agent',
            text: data.text || data.message || '',
            timestamp: data.timestamp || new Date().toISOString(),
          },
        ]);
      }
    };
    const target = typeof globalThis !== 'undefined' ? (globalThis as unknown as EventTarget) : null;
    if (target && 'addEventListener' in target) {
      (target as EventTarget).addEventListener('ggui:agent-data', handler);
      return () => (target as EventTarget).removeEventListener('ggui:agent-data', handler);
    }
    return undefined;
  }, []);

  // Action Contract: sendMessage — "Send Message"
  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    onSendMessage?.(payload);
    setStreamMessages((prev) => [
      ...prev,
      { sender: currentUser, text: trimmed, timestamp: payload.timestamp },
    ]);
    setInputValue('');
  }, [inputValue, currentUser, onSendMessage]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSend();
      }
    },
    [handleSend]
  );

  const messageGroups = groupMessages(allMessages);
  const isSendDisabled = inputValue.trim().length === 0;
  const r = 'var(--ggui-shape-radius-lg, 12px)';
  const rs = 'var(--ggui-shape-radius-sm, 4px)';

  return (
    <div
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        maxHeight: '600px',
        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        background: 'var(--ggui-color-surface, #fafafa)',
        overflow: 'hidden',
        fontFamily: 'inherit',
      }}
      aria-label={`${title} chat window`}
    >
      {/* ===== HEADER ===== */}
      <div
        style={{
          padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--ggui-spacing-2, 8px)',
          flexShrink: 0,
        }}
      >
        <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">{title}</Heading>
        {participantCount !== undefined && (
          <Badge variant="primary" size="sm">{String(participantCount)}</Badge>
        )}
        <div style={{ flex: 1 }} />
      </div>

      {/* ===== MESSAGE LIST ===== */}
      <div
        role="log"
        aria-label="Chat messages"
        aria-live="polite"
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-4, 16px)',
        }}
      >
        {allMessages.length === 0 && (
          <div style={{ padding: 'var(--ggui-spacing-8, 32px)', textAlign: 'center' }}>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No messages yet. Start the conversation!
            </Text>
          </div>
        )}

        {messageGroups.map((group, groupIndex) => {
          const sender = group[0]?.sender || 'Unknown';
          const isCurrentUser = sender === currentUser;

          return (
            <div
              key={`group-${groupIndex}-${group[0]?.timestamp || groupIndex}`}
              style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: isCurrentUser ? 'flex-end' : 'flex-start',
                gap: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              {!isCurrentUser && (
                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                  <div
                    aria-hidden="true"
                    style={{
                      width: '24px',
                      height: '24px',
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      background: getAvatarColor(sender),
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      flexShrink: 0,
                      color: 'var(--ggui-color-neutral-50, #f9fafb)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    }}
                  >
                    {sender.slice(0, 2).toUpperCase()}
                  </div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{sender}</Text>
                </div>
              )}

              {group.map((msg, msgIndex) => {
                const isFirst = msgIndex === 0;
                const isLast = msgIndex === group.length - 1;
                const bubbleRadius = isCurrentUser
                  ? isFirst && isLast ? r
                    : isFirst ? `${r} ${r} ${rs} ${r}`
                    : isLast  ? `${r} ${rs} ${r} ${r}`
                    : `${r} ${rs} ${rs} ${r}`
                  : isFirst && isLast ? r
                    : isFirst ? `${r} ${r} ${r} ${rs}`
                    : isLast  ? `${rs} ${r} ${r} ${r}`
                    : `${rs} ${r} ${r} ${rs}`;

                return (
                  <div
                    key={`msg-${groupIndex}-${msgIndex}`}
                    style={{
                      maxWidth: '75%',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: isCurrentUser ? 'flex-end' : 'flex-start',
                      gap: 'var(--ggui-spacing-1, 4px)',
                    }}
                  >
                    <div
                      style={{
                        padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                        background: isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        borderRadius: bubbleRadius,
                        transition: 'background-color 200ms ease-in-out',
                      }}
                    >
                      <Text
                        variant="bodySmall"
                        color={isCurrentUser ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-onSurface, #18181b)'}
                      >
                        {msg.text || ''}
                      </Text>
                    </div>
                    {isLast && msg.timestamp && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {formatTimestamp(msg.timestamp)}
                      </Text>
                    )}
                  </div>
                );
              })}
            </div>
          );
        })}

        <div ref={messagesEndRef} aria-hidden="true" />
      </div>

      {/* ===== INPUT AREA ===== */}
      <div
        style={{
          padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          display: 'flex',
          alignItems: 'flex-end',
          gap: 'var(--ggui-spacing-2, 8px)',
          flexShrink: 0,
        }}
      >
        <div style={{ flex: 1 }} onKeyDown={handleKeyDown} role="none">
          <Input label="Message" placeholder="Type a message..." value={inputValue} onChange={setInputValue} />
        </div>
        <Button variant="primary" size="md" disabled={isSendDisabled} onClick={handleSend} aria-label="Send message">
          Send
        </Button>
      </div>
    </div>
  );
}
